'use client';

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, ShoppingCart, Truck, PlusCircle, Volume2, Mic, CheckCircle2, Package } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useAssistant } from '@/hooks/useAssistant';
import { useStock } from '@/hooks/useStock';
import { useHistory } from '@/hooks/useHistory';
import { useProductContext } from '@/context/ProductContext';
import { useAuth } from '@/context/AuthContext';
import { useVoice } from '@/hooks/useVoice'; // Added import for useVoice

export default function AcheterPage() {
    const router = useRouter();
    const { products } = useProductContext();
    const { user } = useAuth();
    const { speakIfNecessary } = useVoice(); // Added this line
    const name = user?.name?.split(' ')[0] || 'Marchand';
    const { handleAction, isSpeaking, isListening } = useAssistant(); // Modified this line to remove 'speak'
    const { updateStock } = useStock();
    const { addTransaction } = useHistory();
    const [lastOrdered, setLastOrdered] = useState<string | null>(null);
    const [activeCategory, setActiveCategory] = useState('TOUS');

    const categories = ['TOUS', 'VIVRES', 'FRUITS & L├ëGUMES', 'TUBERCULES', 'BOISSON', 'ENTRETIEN', 'AUTRE'];

    const filteredProducts = activeCategory === 'TOUS'
        ? products
        : products.filter(p => {
            const name = (p.name || '').toUpperCase();
            const isFruitsLegumes = name.includes('TOMATE') || name.includes('OIGNON') || name.includes('CAROTTE') || name.includes('ANANAS') || name.includes('BANANE') || name.includes('FRUIT') || name.includes('L├ëGUME');
            const isTubercules = name.includes('IGNAME') || name.includes('MANIOC') || name.includes('POMME DE TERRE') || name.includes('TUBERCULE');
            const isVivres = (name.includes('RIZ') || name.includes('HUILE') || name.includes('LAIT') || name.includes('ATTI├ëK├ë') || name.includes('PAIN') || name.includes('SUCRE') || name.includes('VIVRE')) && !isFruitsLegumes && !isTubercules;
            const isBoisson = name.includes('EAU') || name.includes('CAF├ë') || name.includes('JUS') || name.includes('BOISSON') || name.includes('BI├êRE') || name.includes('VIN');
            const isEntretien = name.includes('SAVON') || name.includes('JAVEL') || name.includes('PAPIER') || name.includes('ENTRETIEN') || name.includes('LESSIVE');

            if (activeCategory === 'FRUITS & L├ëGUMES') return isFruitsLegumes;
            if (activeCategory === 'TUBERCULES') return isTubercules;
            if (activeCategory === 'VIVRES') return isVivres;
            if (activeCategory === 'BOISSON') return isBoisson;
            if (activeCategory === 'ENTRETIEN') return isEntretien;
            if (activeCategory === 'AUTRE') return !isVivres && !isBoisson && !isEntretien && !isFruitsLegumes && !isTubercules;
            return false;
        });

    const handleOrder = (product: any, qty: number) => {
        const shortName = (product.audioName || product.name).replace(/^[Ll]e\s+/, '').replace(/^[Ll]a\s+/, '').replace(/^[Ll]'\s+/, '');
        const formattedName = qty === 1 ? `un ${shortName}` : `${qty} ${shortName}${shortName.endsWith('s') || shortName.endsWith('x') ? '' : 's'}`;

        updateStock(product.id, qty);
        addTransaction({
            type: 'LIVRAISON',
            productId: product.id,
            productName: product.name,
            quantity: qty,
            price: product.price
        });
        setLastOrdered(product.name);
        speakIfNecessary(`Bravo ${name}, tu as re├ºu ${formattedName}. C'est ajout├⌐ ├á ton stock.`, 'LOW');
        setTimeout(() => setLastOrdered(null), 3000);
    };

    return (
        <main className="min-h-screen bg-slate-50 dark:bg-slate-950 p-3 pb-32 md:pb-64 lg:pb-48 max-w-5xl mx-auto">
            <header className="flex items-center gap-2 md:gap-4 mb-3 md:mb-8 pt-2">
                <button
                    onClick={() => router.push('/')}
                    className="w-9 h-9 md:w-12 md:h-12 bg-white dark:bg-slate-800 rounded-full shadow-md flex items-center justify-center text-slate-600 dark:text-slate-300 active:scale-90 transition-transform shrink-0"
                >
                    <ChevronLeft size={20} className="md:w-8 md:h-8" />
                </button>
                <h1 className="text-lg md:text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter truncate">Acheter / Re├ºu</h1>
            </header>

            <section className="bg-blue-600 rounded-[24px] md:rounded-[40px] p-4 md:p-12 text-white mb-4 md:mb-8 shadow-xl shadow-blue-100 dark:shadow-blue-900/20 overflow-hidden relative">
                <div className="relative z-10">
                    <div className="flex items-center gap-2 md:gap-3 mb-2 md:mb-4">
                        <Truck size={24} className="md:w-10 md:h-10" />
                        <span className="font-black uppercase tracking-widest text-blue-100 text-[9px] md:text-base">Nouvel Arrivage</span>
                    </div>
                    <p className="text-sm md:text-2xl font-bold max-w-2xl leading-tight">
                        {name}, quand tu re├ºois des produits, appuie sur le bouton <PlusCircle className="inline w-4 h-4 md:w-6 md:h-6" /> ou parle-moi simplement.
                    </p>
                </div>
                <Truck size={180} className="absolute -right-8 -bottom-8 text-white/10 rotate-12 hidden md:block" />
                <Truck size={60} className="absolute -right-2 -bottom-2 text-white/10 rotate-12 md:hidden" />
            </section>

            {/* Filtres Cat├⌐gories */}
            <div className="flex gap-2 md:gap-3 overflow-x-auto pb-4 md:pb-6 scrollbar-hide -mx-4 px-4 mb-4 md:mb-6">
                {categories.map(cat => (
                    <button
                        key={cat}
                        onClick={() => setActiveCategory(cat)}
                        className={`px-6 md:px-8 py-3 md:py-4 rounded-[16px] md:rounded-[20px] font-black text-xs md:text-sm uppercase tracking-widest transition-all whitespace-nowrap border-[1.5px] md:border-2 ${activeCategory === cat ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white dark:bg-slate-900 border-slate-100 dark:border-slate-800 text-slate-400'}`}
                    >
                        {cat}
                    </button>
                ))}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
                {filteredProducts.map(product => (
                    <motion.div
                        key={product.id}
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="bg-white dark:bg-slate-900 p-5 md:p-6 rounded-[28px] md:rounded-[35px] border-2 border-slate-100 dark:border-slate-800 flex flex-col gap-5 md:gap-6 shadow-sm hover:border-blue-200 dark:hover:border-blue-900 transition-colors group overflow-hidden relative"
                    >
                        <div className="flex items-center gap-3 md:gap-4 relative z-10">
                            <div className={`w-16 h-16 md:w-20 md:h-20 shrink-0 rounded-[20px] md:rounded-3xl ${product.color || 'bg-slate-100'} flex items-center justify-center shadow-inner overflow-hidden border-2 border-white dark:border-slate-700 bg-white/50 backdrop-blur-sm`}>
                                {product.imageUrl ? (
                                    <img src={product.imageUrl} alt={product.name} className="w-full h-full object-contain p-1 group-hover:scale-110 transition-transform duration-500" />
                                ) : (
                                    <Package size={28} className="text-slate-300 md:w-9 md:h-9" />
                                )}
                            </div>
                            <div className="min-w-0">
                                <h3 className="font-black text-slate-800 dark:text-white uppercase text-base md:text-lg leading-tight mb-1 truncate">{product.name}</h3>
                                <div className="flex items-center gap-2">
                                    <span className="text-[9px] md:text-[10px] font-black text-blue-600 bg-blue-50 dark:bg-blue-900/30 px-2 py-0.5 rounded-full uppercase tracking-widest border border-blue-100 dark:border-blue-800">Enregistrer</span>
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center gap-2 md:gap-3 relative z-10">
                            {[5, 10, 20].map(qty => (
                                <button
                                    key={qty}
                                    onClick={() => handleOrder(product, qty)}
                                    className="flex-1 h-10 md:h-16 bg-slate-50 dark:bg-slate-800/80 hover:bg-blue-50 dark:hover:bg-blue-900/40 rounded-lg md:rounded-2xl flex items-center justify-center font-black text-sm md:text-xl text-slate-900 dark:text-white border-2 border-slate-100 dark:border-slate-700 active:bg-blue-600 active:text-white active:border-blue-600 transition-all shadow-sm"
                                >
                                    +{qty}
                                </button>
                            ))}
                        </div>

                        {/* Decoration Icon background */}
                        {!product.imageUrl && (
                            <div className="absolute -right-4 -bottom-4 opacity-5 pointer-events-none transition-opacity group-hover:opacity-10">
                                <Package size={120} />
                            </div>
                        )}
                    </motion.div>
                ))}
            </div>

            {/* Micro Global (Centr├⌐ et Responsive) */}
            <div className="fixed bottom-6 left-0 right-0 flex justify-center px-4 md:px-6 pointer-events-none z-50">
                <motion.button
                    onClick={handleAction}
                    whileTap={{ scale: 0.95 }}
                    className={`h-22 w-auto px-6 md:h-32 md:px-16 rounded-[28px] md:rounded-[50px] shadow-2xl text-white flex items-center justify-center gap-4 md:gap-6 pointer-events-auto border-4 border-white dark:border-slate-900 transition-all ${isListening ? 'bg-red-500 scale-105 md:scale-110 animate-pulse' : 'bg-blue-600 active:bg-blue-700'}`}
                >
                    <div className={`p-4 md:p-6 rounded-2xl md:rounded-3xl ${isSpeaking || isListening ? 'bg-white text-blue-600' : 'bg-white/20 text-white'} transition-all duration-300 shrink-0`}>
                        <Mic size={28} className="md:w-12 md:h-12 md:scale-110" fill={isSpeaking || isListening ? "currentColor" : "none"} strokeWidth={3} />
                    </div>
                    <div className="flex flex-col items-start pr-2 md:pr-4 text-left">
                        <span className="text-xl md:text-3xl font-black leading-none uppercase">{isListening ? "├ëCOUTE..." : "PARLER"}</span>
                        <span className="text-[10px] md:text-base font-bold opacity-80 italic tracking-tighter text-blue-100 uppercase">"J'ai re├ºu 10 pains"</span>
                    </div>
                </motion.button>
            </div>

            <AnimatePresence>
                {lastOrdered && (
                    <motion.div
                        initial={{ y: 50, opacity: 0 }}
                        animate={{ y: 0, opacity: 1 }}
                        exit={{ y: 50, opacity: 0 }}
                        className="fixed bottom-40 left-1/2 -translate-x-1/2 bg-slate-900 dark:bg-blue-900 bg-opacity-95 text-white px-10 py-5 rounded-full font-black uppercase tracking-widest text-sm shadow-2xl border-4 border-white/20 z-[60] flex items-center gap-4 whitespace-nowrap"
                    >
                        <CheckCircle2 size={24} className="text-emerald-400" /> {lastOrdered} AJOUT├ë AU STOCK !
                    </motion.div>
                )}
            </AnimatePresence>
        </main>
    );
}

'use client';

import React, { useState, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    LayoutDashboard,
    Package,
    History as HistoryIcon,
    Settings,
    TrendingUp,
    AlertCircle,
    Plus,
    Trash2,
    Edit2,
    Download,
    Search,
    ChevronRight,
    Filter,
    RotateCcw,
    DollarSign,
    CheckCircle2,
    X,
    Users,
    Store,
    UserCircle,
    ArrowLeft,
    LogOut,
    Bell,
    Send
} from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useProductContext } from '@/context/ProductContext';
import { useHistory } from '@/hooks/useHistory';
import { useStock } from '@/hooks/useStock';
import { useProfileContext } from '@/context/ProfileContext';
import { useAuth } from '@/context/AuthContext';
import { useNotifications } from '@/context/NotificationContext';
import { useConfirm } from '@/context/ConfirmContext';
import { supabase } from '@/lib/supabase';
import { syncGlobalCatalog } from '@/services/product.service';
import { AddProductModal } from '@/components/AddProductModal';

type AdminTab = 'OVERVIEW' | 'PROFILES' | 'PRODUCTS' | 'HISTORY' | 'SYSTEM' | 'NOTIFICATIONS' | 'USERS';

export default function ProfessionalAdminPage() {
    const router = useRouter();
    const { user, isAuthenticated } = useAuth();
    const { products, addProduct, deleteProduct } = useProductContext();
    const { history, clearHistory } = useHistory();
    const { stock } = useStock();
    const { profiles, activeProfile, addProfile, deleteProfile, setActiveProfile } = useProfileContext();
    const { notifications, sendNotification, deleteNotification } = useNotifications();
    const confirm = useConfirm();

    const [activeTab, setActiveTab] = useState<AdminTab>('OVERVIEW');
    const [searchQuery, setSearchQuery] = useState('');
    const [showSuccess, setShowSuccess] = useState(false);
    const [showNewProfileModal, setShowNewProfileModal] = useState(false);
    const [showAddProductModal, setShowAddProductModal] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);

    const [newNotification, setNewNotification] = useState({ title: '', message: '', target_id: 'ALL', type: 'INFO' as any });

    const [newProfileData, setNewProfileData] = useState({ name: '', merchantName: '' });
    const [allUsers, setAllUsers] = useState<any[]>([]);
    const [globalHistory, setGlobalHistory] = useState<any[]>([]);
    const [globalStock, setGlobalStock] = useState<any>({});

    const fetchAllUsers = async () => {
        const { data } = await supabase
            .from('profiles')
            .select('*')
            .order('created_at', { ascending: false });
        if (data) setAllUsers(data);
    };

    const deleteUser = async (userId: string) => {
        const ok = await confirm({
            title: 'Supprimer cet utilisateur ?',
            message: 'Cette action est irr├⌐versible. Le compte sera d├⌐finitivement supprim├⌐.',
            confirmLabel: 'Supprimer',
            dangerMode: true
        });
        if (!ok) return;
        const { error } = await supabase.from('profiles').delete().eq('id', userId);
        if (!error) {
            triggerSuccess();
            fetchAllUsers();
        }
    };

    const toggleUserRole = async (userId: string, currentRole: string) => {
        const newRole = currentRole === 'SUPERVISOR' ? 'MERCHANT' : 'SUPERVISOR';
        const { error } = await supabase.from('profiles').update({ role: newRole }).eq('id', userId);
        if (!error) {
            triggerSuccess();
            fetchAllUsers();
        }
    };

    const fetchGlobalData = async () => {
        // Fetch all transactions
        const { data: transactions } = await supabase
            .from('transactions')
            .select('*, profiles:store_id(full_name)')
            .order('created_at', { ascending: false });

        if (transactions) {
            setGlobalHistory(transactions.map((t: any) => ({
                id: t.id,
                type: t.type,
                productId: t.product_id,
                productName: t.product_name,
                quantity: t.quantity,
                price: t.price,
                timestamp: new Date(t.created_at).getTime(),
                clientName: t.client_name,
                status: t.status,
                merchantName: t.profiles?.full_name || 'Inconnu'
            })));
        }

        // Fetch all stock levels
        const { data: stockData } = await supabase
            .from('stock')
            .select('*');

        if (stockData) {
            const aggregatedStock: any = {};
            stockData.forEach((s: any) => {
                aggregatedStock[s.product_id] = (aggregatedStock[s.product_id] || 0) + s.quantity;
            });
            setGlobalStock(aggregatedStock);
        }
    };

    React.useEffect(() => {
        if (activeTab === 'USERS') fetchAllUsers();
        if (activeTab === 'OVERVIEW' || activeTab === 'HISTORY') fetchGlobalData();
    }, [activeTab]);

    React.useEffect(() => {
        if (isAuthenticated && user?.role !== 'SUPERVISOR') {
            router.push('/');
        }
    }, [isAuthenticated, user, router]);

    // Business Logic / Analytics matching Merchant Colors
    const stats = useMemo(() => {
        const dataToUse = globalHistory.length > 0 ? globalHistory : history;
        const stockToUse = Object.keys(globalStock).length > 0 ? globalStock : stock;

        const totalVolume = dataToUse.reduce((acc, t) => acc + t.price, 0);
        const totalSales = dataToUse.filter(t => t.type === 'VENTE').reduce((acc, t) => acc + t.price, 0);
        const outstandingDebt = dataToUse.filter(t => t.status === 'DETTE').reduce((acc, t) => acc + t.price, 0);
        const inventoryValue = products.reduce((acc, p) => acc + (p.price * (stockToUse[p.id] || 0)), 0);

        return { totalVolume, totalSales, outstandingDebt, inventoryValue };
    }, [history, products, stock, globalHistory, globalStock]);

    const filteredHistory = useMemo(() => {
        const dataToUse = globalHistory.length > 0 ? globalHistory : history;
        return dataToUse.filter(t =>
            t.productName.toLowerCase().includes(searchQuery.toLowerCase()) ||
            (t.clientName && t.clientName.toLowerCase().includes(searchQuery.toLowerCase())) ||
            (t.merchantName && t.merchantName.toLowerCase().includes(searchQuery.toLowerCase()))
        );
    }, [history, globalHistory, searchQuery]);

    const triggerSuccess = () => {
        setShowSuccess(true);
        setTimeout(() => setShowSuccess(false), 2000);
    };

    const handleCreateProfile = (e: React.FormEvent) => {
        e.preventDefault();
        if (newProfileData.name && newProfileData.merchantName) {
            addProfile({
                name: newProfileData.name,
                merchantName: newProfileData.merchantName,
                status: 'ACTIVE'
            });
            setNewProfileData({ name: '', merchantName: '' });
            setShowNewProfileModal(false);
            triggerSuccess();
        }
    };

    return (
        <div className="min-h-screen bg-[#f8fafc] dark:bg-slate-950 flex flex-col md:flex-row">
            {/* Sidebar devient compact sur desktop, escamotable sur mobile */}
            <aside className="w-full md:w-72 p-2 sm:p-4 md:p-6 md:fixed md:h-screen z-40 bg-transparent shrink-0">
                <div className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl md:h-full rounded-[24px] md:rounded-[40px] shadow-lg md:shadow-2xl border border-slate-100 dark:border-slate-800 flex flex-col p-4 md:p-8">
                    <div className="flex items-center justify-between md:justify-start gap-3 sm:gap-4 mb-4 md:mb-12">
                        <div className="flex items-center gap-3">
                            <div className="bg-emerald-600 p-2 md:p-3 rounded-xl md:rounded-2xl shadow-lg shrink-0">
                                <LayoutDashboard size={20} className="text-white md:w-7 md:h-7" />
                            </div>
                            <div>
                                <span className="font-black text-lg md:text-2xl uppercase tracking-tighter text-slate-900 dark:text-white block leading-none">ADMIN</span>
                                <span className="text-emerald-600 font-bold text-[8px] md:text-xs uppercase tracking-widest hidden sm:block">Supervision</span>
                            </div>
                        </div>
                        <button
                            onClick={() => router.push('/')}
                            className="md:hidden flex items-center justify-center p-2 bg-rose-50 dark:bg-rose-900/20 rounded-xl text-rose-500"
                        >
                            <LogOut size={18} />
                        </button>
                    </div>

                    <nav className="flex md:flex-col gap-2 md:gap-3 flex-1 overflow-x-auto md:overflow-y-auto pb-2 md:pb-0 scrollbar-hide -mx-2 px-2 md:mx-0 md:px-0">
                        <SidebarLink active={activeTab === 'OVERVIEW'} onClick={() => setActiveTab('OVERVIEW')} icon={TrendingUp} label="Bilan Global" color="emerald" />
                        <SidebarLink active={activeTab === 'USERS'} onClick={() => setActiveTab('USERS')} icon={Users} label="Utilisateurs" color="blue" />
                        <SidebarLink active={activeTab === 'PROFILES'} onClick={() => setActiveTab('PROFILES')} icon={Store} label="Commer├ºants" color="emerald" />
                        <SidebarLink active={activeTab === 'PRODUCTS'} onClick={() => setActiveTab('PRODUCTS')} icon={Package} label="Catalogue" color="amber" />
                        <SidebarLink active={activeTab === 'HISTORY'} onClick={() => setActiveTab('HISTORY')} icon={HistoryIcon} label="Historique" color="purple" />
                        <SidebarLink active={activeTab === 'NOTIFICATIONS'} onClick={() => setActiveTab('NOTIFICATIONS')} icon={Bell} label="Alertes" color="rose" />
                        <SidebarLink active={activeTab === 'SYSTEM'} onClick={() => setActiveTab('SYSTEM')} icon={Settings} label="Syst├¿me" color="rose" />
                    </nav>

                    <button
                        onClick={() => router.push('/')}
                        className="hidden md:flex mt-6 sm:mt-8 items-center justify-center gap-3 bg-rose-50 dark:bg-rose-900/20 hover:bg-rose-100 py-4 sm:py-5 rounded-2xl sm:rounded-3xl font-black uppercase text-[10px] sm:text-xs tracking-widest text-rose-500 transition-all border border-rose-100 dark:border-rose-800 active:scale-95"
                    >
                        <LogOut size={16} className="sm:w-5 sm:h-5" /> D├⌐connexion
                    </button>
                </div>
            </aside>

            {/* Content Area */}
            <main className="flex-1 md:ml-72 p-4 sm:p-6 md:p-10 pb-32">
                {/* Profile Header Card */}
                <header className="flex flex-col lg:flex-row items-start lg:items-center justify-between gap-4 sm:gap-6 mb-8 sm:mb-12">
                    <div className="flex items-center gap-4 sm:gap-6">
                        <div className="w-16 h-16 sm:w-20 sm:h-20 bg-emerald-600 rounded-[24px] sm:rounded-[32px] flex items-center justify-center shadow-lg">
                            <Store size={32} className="text-white sm:w-10 sm:h-10" />
                        </div>
                        <div>
                            <p className="text-emerald-600 font-black text-[8px] sm:text-[10px] uppercase tracking-[0.2em] mb-1">Superviseur</p>
                            <h1 className="text-2xl sm:text-4xl font-black text-slate-900 dark:text-white uppercase tracking-tighter leading-tight">
                                {activeTab === 'OVERVIEW' && "Bilan Global"}
                                {activeTab === 'USERS' && "Utilisateurs"}
                                {activeTab === 'PROFILES' && "Marchands"}
                                {activeTab === 'PRODUCTS' && "Catalogue"}
                                {activeTab === 'HISTORY' && "Journal"}
                                {activeTab === 'NOTIFICATIONS' && "Alertes"}
                                {activeTab === 'SYSTEM' && "Syst├¿me"}
                            </h1>
                        </div>
                    </div>

                    <div className="hidden sm:flex bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl px-6 py-4 rounded-[32px] shadow-sm border border-slate-100 dark:border-slate-800 items-center gap-3">
                        <div className="w-10 h-10 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center text-slate-400">
                            <UserCircle size={24} />
                        </div>
                        <div>
                            <span className="text-[8px] font-black text-slate-300 dark:text-slate-600 uppercase tracking-widest block leading-none mb-1">Actif</span>
                            <span className="font-black text-slate-900 dark:text-white uppercase tracking-tight text-xs">{activeProfile?.name || '---'}</span>
                        </div>
                    </div>
                </header>

                <AnimatePresence mode="wait">
                    {activeTab === 'OVERVIEW' && (
                        <motion.div key="overview" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="space-y-6 sm:space-y-10">
                            <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-6">
                                <StatCard label="Caisse" value={`${stats.totalSales} F`} icon={DollarSign} color="emerald" />
                                <StatCard label="Dettes" value={`${stats.outstandingDebt} F`} icon={AlertCircle} color="rose" />
                                <StatCard label="Stock" value={`${stats.inventoryValue} F`} icon={Package} color="blue" />
                                <StatCard label="Volume" value={`${stats.totalVolume} F`} icon={TrendingUp} color="amber" />
                            </div>

                            <div className="grid grid-cols-1 xl:grid-cols-2 gap-6 sm:gap-10">
                                {/* Recent Activity with Merchant-style rows */}
                                <section className="bg-white dark:bg-slate-900 p-6 sm:p-10 rounded-[32px] sm:rounded-[48px] shadow-sm border border-slate-50 dark:border-slate-800">
                                    <h3 className="font-black text-slate-400 text-[10px] sm:text-xs uppercase tracking-widest mb-6 sm:mb-8 text-center md:text-left">Derniers Mouvements</h3>
