                                                    </div>
                                                </div>
                                            </div>
                                            <div className="text-right shrink-0">
                                                <p className={`font-bold text-[14px] ${t.status === 'DETTE' ? 'text-red-500' : t.type === 'VENTE' ? 'text-emerald-600' : 'text-slate-400'}`}>
