'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, PlayCircle, PauseCircle, Headphones, Play, Sparkles } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useVoice } from '@/hooks/useVoice';

export default function FormationPage() {
    const router = useRouter();
    const { speakIfNecessary, stopSpeaking, isSpeaking } = useVoice();
    const [playingId, setPlayingId] = useState<number | null>(null);

    const tutorials = [
        { id: 1, title: 'Comment vendre vocalement', duration: '1 min', text: "Pour vendre, appuie sur le gros bouton du microphone en bas de l'├⌐cran principal. Ensuite, dis simplement 'Vend deux tomates ├á Fatou' et l'application s'occupe du reste. Tu peux aussi pr├⌐ciser si c'est ├á cr├⌐dit." },
        { id: 2, title: 'Ajouter un nouveau produit', duration: '45 sec', text: "Va dans la section Acheter, puis appuie sur le bouton Ajouter. Prends une belle photo de ton produit avec ton t├⌐l├⌐phone, donne-lui un nom clair, fixe son prix de vente et la quantit├⌐ que tu as re├ºue." },
        { id: 3, title: 'Comment voir qui me doit', duration: '30 sec', text: "Ouvre le carnet de dettes depuis le menu principal. Tu verras la liste de tous tes clients qui ne t'ont pas encore pay├⌐. Si un client te paie, clique sur son nom et appuie sur 'Marquer comme pay├⌐'." },
        { id: 4, title: 'Comprendre mon bilan', duration: '1 min', text: "La page Bilan te montre si tu gagnes de l'argent ou si tu en perds. L'application calcule automatiquement tes b├⌐n├⌐fices en soustrayant tes achats de tes ventes. L'intelligence artificielle te donnera aussi des conseils vocaux." },
    ];

    const togglePlay = (tuto: any) => {
        if (playingId === tuto.id && isSpeaking) {
            stopSpeaking();
            setPlayingId(null);
        } else {
            speakIfNecessary(tuto.text, 'NORMAL');
            setPlayingId(tuto.id);
        }
    };

    useEffect(() => {
        return () => stopSpeaking();
    }, [stopSpeaking]);

    return (
        <main className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-32">
            {/* Header Color├⌐ (Card Overlap Style) */}
            <div className="bg-cyan-600 pt-8 pb-32 px-4 rounded-b-[2.5rem] relative shadow-lg">
                <div className="flex justify-between items-center max-w-lg mx-auto mb-6">
                    <button
                        onClick={() => {
                            stopSpeaking();
                            router.back();
                        }}
                        className="w-10 h-10 bg-white text-cyan-600 rounded-full flex items-center justify-center active:scale-95 transition-transform shadow-sm"
                    >
                        <ArrowLeft size={20} />
                    </button>
                    <div className="text-center flex-1 pr-10">
                        <h1 className="text-white font-bold text-lg tracking-wide uppercase">Apprentissage</h1>
                        <p className="text-cyan-100/60 text-[10px] font-bold uppercase tracking-widest mt-0.5">├ëcouter & Apprendre</p>
                    </div>
                </div>
            </div>

            {/* Main Content Overlap */}
            <div className="px-4 max-w-lg mx-auto relative -mt-20 z-10 space-y-6">
                {/* Intro Card */}
                <div className="bg-white dark:bg-slate-900 p-8 rounded-[32px] shadow-xl border border-slate-100 dark:border-slate-800 relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none">
                        <Headphones size={80} className="text-cyan-600 rotate-12" />
                    </div>

                    <div className="relative z-10">
                        <div className="flex items-center gap-2 mb-4">
                            <Sparkles size={16} className="text-amber-500" />
                            <span className="text-[10px] font-black text-cyan-600 uppercase tracking-[0.2em]">Coach Personnel</span>
                        </div>
                        <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tighter uppercase leading-none mb-3">
                            Tutoriels Audio
                        </h2>
                        <p className="text-slate-500 dark:text-slate-400 font-bold text-[10px] uppercase tracking-widest leading-loose">
                            Appuie sur lecture pour ├⌐couter le coach t'expliquer comment utiliser l'application comme un expert.
                        </p>
                    </div>
                </div>

                {/* Tutorials List */}
                <div className="space-y-4">
                    <div className="flex items-center gap-2 ml-4">
                        <div className="w-1 h-3 bg-cyan-500 rounded-full" />
                        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Le├ºons disponibles</h3>
                    </div>

                    {tutorials.map((tuto) => {
                        const isPlaying = playingId === tuto.id && isSpeaking;
                        return (
                            <motion.button
                                key={tuto.id}
                                whileTap={{ scale: 0.98 }}
                                onClick={() => togglePlay(tuto)}
                                className={`w-full bg-white dark:bg-slate-900 p-5 rounded-[28px] border transition-all flex items-center gap-5 text-left shadow-sm ${isPlaying ? 'border-cyan-500 ring-2 ring-cyan-500/10' : 'border-slate-100 dark:border-slate-800'}`}
                            >
                                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 transition-colors ${isPlaying ? 'bg-cyan-600 text-white shadow-lg' : 'bg-slate-50 dark:bg-slate-800 text-slate-400'}`}>
                                    {isPlaying ? (
                                        <PauseCircle size={24} className="animate-pulse" />
                                    ) : (
                                        <PlayCircle size={24} />
                                    )}
                                </div>
                                <div className="flex-1 min-w-0">
                                    <h4 className="font-black uppercase tracking-tight text-slate-900 dark:text-white text-xs leading-none mb-2 truncate">
                                        {tuto.title}
                                    </h4>
                                    <div className="flex items-center gap-2 text-[8px] font-black text-slate-400 uppercase tracking-widest">
                                        <span className="flex items-center gap-1">
                                            <Play size={8} fill="currentColor" /> {tuto.duration}
                                        </span>
                                        <span className="w-1 h-1 bg-slate-200 rounded-full" />
                                        <span className="text-cyan-600">Audio</span>
                                    </div>
                                </div>
                                {isPlaying && (
                                    <div className="flex gap-0.5 items-end h-3">
                                        {[1, 2, 3].map(i => (
                                            <motion.div
                                                key={i}
                                                animate={{ height: [4, 12, 4] }}
                                                transition={{ duration: 0.5, repeat: Infinity, delay: i * 0.1 }}
                                                className="w-0.5 bg-cyan-500 rounded-full"
                                            />
                                        ))}
                                    </div>
                                )}
                            </motion.button>
                        );
                    })}
                </div>
            </div>
        </main>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Phone, Lock, ChevronRight, UserPlus, AlertCircle, CheckCircle2, Delete } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';

export default function LoginPage() {
    const router = useRouter();
    const { login, isAuthenticated, user } = useAuth();

    const [phoneNumber, setPhoneNumber] = useState('');
    const [pin, setPin] = useState('');
    const [error, setError] = useState('');
    const [step, setStep] = useState<'PHONE' | 'PIN'>('PHONE');

    const getDashboardPath = (role: string | undefined) => {
        switch (role) {
            case 'SUPERVISOR': return '/admin';
            case 'PRODUCER': return '/producteur';
            case 'COOPERATIVE': return '/cooperative';
            case 'FIELD_AGENT': return '/agent';
            case 'MERCHANT':
            default: return '/commercant';
        }
    };

    useEffect(() => {
        if (isAuthenticated && user) {
            router.push(getDashboardPath(user.role));
        }
    }, [isAuthenticated, user, router]);

    // Handle Hardware Back Button
    useEffect(() => {
        const handlePopState = (e: PopStateEvent) => {
            if (step === 'PIN') {
                e.preventDefault();
                setStep('PHONE');
                setPin('');
                // Stay on the same page but change step
                window.history.pushState(null, '', window.location.pathname);
            }
        };

        if (step === 'PIN') {
            window.history.pushState(null, '', window.location.pathname);
            window.addEventListener('popstate', handlePopState);
        }

        return () => window.removeEventListener('popstate', handlePopState);
    }, [step]);

    if (isAuthenticated) return null;

    const handlePhoneSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (phoneNumber.length >= 8) {
            setStep('PIN');
            setError('');
        } else {
            setError('Num├⌐ro de t├⌐l├⌐phone invalide');
        }
    };

    const handlePinPress = (num: string) => {
        if (pin.length < 4) {
            const newPin = pin + num;
            setPin(newPin);
            if (newPin.length === 4) {
                handleLogin(newPin);
            }
        }
    };

    const handleLogin = async (finalPin: string) => {
        const success = await login(phoneNumber, finalPin);
        if (success) {
            // Success handled by useEffect
        } else {
            setError('PIN incorrect ou compte inexistant');
            setPin('');
        }
    };

    return (
        <main className="min-h-screen bg-white dark:bg-slate-950 flex flex-col p-3 items-center justify-center relative overflow-hidden">
            {/* Background Accents (Merchant Style) */}
            <div className="absolute -top-20 -right-20 w-64 h-64 bg-emerald-50 rounded-full blur-3xl opacity-50" />
            <div className="absolute -bottom-20 -left-20 w-64 h-64 bg-blue-50 rounded-full blur-3xl opacity-50" />

            <div className="w-full max-w-md relative z-10">
                {/* Logo / Header */}
                <header className="text-center mb-4 sm:mb-10">
                    <motion.div
                        initial={{ scale: 0.5, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        className="w-14 h-14 sm:w-24 sm:h-24 bg-emerald-600 rounded-2xl sm:rounded-[32px] mx-auto mb-3 sm:mb-6 flex items-center justify-center shadow-xl sm:shadow-2xl shadow-emerald-100"
                    >
                        <Lock size={28} className="text-white sm:w-12 sm:h-12" />
                    </motion.div>
                    <h1 className="text-xl sm:text-4xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Bienvenue</h1>
                    <p className="text-slate-500 font-bold uppercase tracking-widest text-[9px] sm:text-xs mt-1 sm:mt-2">Connectez-vous pour continuer</p>
                </header>

                <AnimatePresence mode="wait">
                    {step === 'PHONE' ? (
                        <motion.form
                            key="phone-step"
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 20 }}
                            onSubmit={handlePhoneSubmit}
                            className="space-y-6"
                        >
                            <div className="relative">
                                <label className="text-[9px] font-black uppercase tracking-[0.3em] text-slate-400 ml-5 mb-1 block">Num├⌐ro de T├⌐l├⌐phone</label>
                                <div className="relative">
                                    <Phone className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                                    <input
                                        autoFocus
                                        type="tel"
                                        placeholder="0102030405"
                                        value={phoneNumber}
                                        onChange={e => setPhoneNumber(e.target.value)}
                                        className="w-full bg-slate-50 dark:bg-slate-900 border-[3px] border-slate-100 dark:border-slate-800 rounded-[24px] p-5 pl-14 font-black text-xl text-slate-900 dark:text-white outline-none focus:border-emerald-500 transition-all placeholder:text-slate-200"
                                    />
                                </div>
                            </div>

                            {error && (
                                <div className="flex items-center gap-3 bg-rose-50 p-4 rounded-2xl text-rose-600 font-bold text-sm">
                                    <AlertCircle size={20} /> {error}
                                </div>
                            )}

                            <button
                                type="submit"
                                className="w-full bg-slate-900 dark:bg-emerald-600 text-white p-5 rounded-[24px] font-black uppercase tracking-[0.2em] text-lg shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3"
                            >
                                Suivant <ChevronRight size={24} />
                            </button>

                            <button
                                type="button"
                                onClick={() => router.push('/signup')}
                                className="w-full py-2 text-slate-400 font-black uppercase text-[9px] tracking-widest hover:text-emerald-600 transition-colors"
                            >
                                Cr├⌐er un nouveau compte
                            </button>
                        </motion.form>
                    ) : (
                        <motion.div
                            key="pin-step"
                            initial={{ opacity: 0, x: 20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: -20 }}
                            className="flex flex-col items-center w-full"
                        >
                            <label className="text-[9px] sm:text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-6 sm:mb-8">Entrez votre PIN secret</label>

                            {/* PIN Display Dots */}
                            <div className="flex gap-4 sm:gap-6 mb-8 sm:mb-12">
                                {[0, 1, 2, 3].map(i => (
                                    <div
                                        key={i}
                                        className={`w-4 h-4 sm:w-6 sm:h-6 rounded-full border-[3px] sm:border-4 transition-all duration-100 ${pin.length > i ? 'bg-emerald-600 border-emerald-600 scale-125' : 'bg-transparent border-slate-200'}`}
                                    />
                                ))}
                            </div>

                            {error && (
                                <div className="mb-8 flex items-center gap-3 bg-rose-50 p-4 rounded-2xl text-rose-600 font-bold text-sm w-full">
                                    <AlertCircle size={20} /> {error}
                                </div>
                            )}

                            {/* Wave-style Number Pad */}
                            <div className="grid grid-cols-3 gap-3 sm:gap-6 w-full max-w-[280px] sm:max-w-[320px]">
                                {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                                    <button
                                        key={num}
                                        onClick={() => handlePinPress(num.toString())}
                                        className="aspect-square bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[18px] sm:rounded-[24px] flex items-center justify-center text-2xl sm:text-3xl font-black text-slate-900 dark:text-white shadow-sm sm:shadow-lg active:scale-90 active:bg-emerald-50 transition-all hover:border-emerald-200"
                                    >
                                        {num}
                                    </button>
                                ))}
                                <button
                                    onClick={() => setStep('PHONE')}
                                    className="aspect-square flex items-center justify-center text-slate-300 hover:text-rose-500 transition-colors"
                                >
                                    <ArrowBackIcon />
                                </button>
                                <button
                                    onClick={() => handlePinPress('0')}
                                    className="aspect-square bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[18px] sm:rounded-[24px] flex items-center justify-center text-2xl sm:text-3xl font-black text-slate-900 dark:text-white shadow-sm sm:shadow-lg active:scale-90 active:bg-emerald-50 transition-all hover:border-emerald-200"
                                >
                                    0
                                </button>
                                <button
                                    onClick={() => setPin(prev => prev.slice(0, -1))}
                                    className="aspect-square flex items-center justify-center text-slate-300 hover:text-slate-900 transition-colors"
                                >
                                    <Delete size={28} className="sm:w-8 sm:h-8" />
                                </button>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </main>
    );
}

function ArrowBackIcon() {
    return (
        <motion.div whileHover={{ x: -2 }} className="flex items-center gap-1 font-black uppercase text-[10px] tracking-widest text-slate-300">
            <ChevronRight className="rotate-180" size={20} />
        </motion.div>
    );
}

