'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    ChevronLeft,
    User,
    Phone,
    ShieldCheck,
    LogOut,
    Trash2,
    Bell,
    HelpCircle,
    Globe,
    KeyRound,
    CheckCircle2,
    AlertTriangle,
    RefreshCw
} from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { useProfileContext } from '@/context/ProfileContext';
import { SupportCenter } from '@/components/SupportCenter';
import { useConfirm } from '@/context/ConfirmContext';
import { useProductContext } from '@/context/ProductContext';
import { useSync } from '@/context/SyncContext';
import { supabase } from '@/lib/supabase';
import { syncGlobalCatalog } from '@/services/product.service';
import { useVoiceContext } from '@/context/VoiceContext';

export default function ProfilePage() {
    const router = useRouter();
    const { user, logout, updatePin, updateLanguage } = useAuth();
    const { activeProfile } = useProfileContext();
    const { verbosity, setVerbosity } = useVoiceContext();
    // syncGlobalCatalog is now imported directly
    const { syncAll, syncPendingCount, isSyncing, isOnline, lastSyncError } = useSync();
    const confirm = useConfirm();
    const [isForceSyncing, setIsForceSyncing] = useState(false);

    // UI States
    const [isSupportOpen, setIsSupportOpen] = useState(false);
    const [userLanguage, setUserLanguage] = useState('Fran├ºais');
    const [showPinModal, setShowPinModal] = useState(false);
    const [newPin, setNewPin] = useState('');
    const [confirmPin, setConfirmPin] = useState('');
    const [pinError, setPinError] = useState('');
    const [pinSuccess, setPinSuccess] = useState(false);
    const [notifsEnabled, setNotifsEnabled] = useState(true);

    // Role-based theme configuration
    const getRoleTheme = () => {
        switch (user?.role) {
            case 'PRODUCER':
                return {
                    primary: 'bg-amber-500',
                    secondary: 'text-amber-600',
                    bg: 'bg-amber-50',
                    darkBg: 'bg-amber-900/10',
                    label: 'Producteur',
                    homePath: '/producteur'
                };
            case 'COOPERATIVE':
                return {
                    primary: 'bg-purple-600',
                    secondary: 'text-purple-600',
                    bg: 'bg-purple-50',
                    darkBg: 'bg-purple-900/10',
                    label: 'Responsable Coop',
                    homePath: '/cooperative'
                };
            default:
                return {
                    primary: 'bg-emerald-600',
                    secondary: 'text-emerald-600',
                    bg: 'bg-emerald-50',
                    darkBg: 'bg-emerald-900/10',
                    label: 'Commer├ºant',
                    homePath: '/commercant'
                };
        }
    };

    const theme = getRoleTheme();

    useEffect(() => {
        const savedLang = localStorage.getItem('assistant_language');
        if (savedLang) setUserLanguage(savedLang);
    }, []);

    const handleLanguageChange = (lang: string) => {
        setUserLanguage(lang);
        updateLanguage(lang);
    };

    const handlePinUpdate = async () => {
        if (newPin.length < 4) {
            setPinError('Le code PIN doit faire au moins 4 chiffres');
            return;
        }
        if (newPin !== confirmPin) {
            setPinError('Les codes ne correspondent pas');
            return;
        }

        const success = await updatePin(newPin);
        if (success) {
            setPinSuccess(true);
            setTimeout(() => {
                setShowPinModal(false);
                setPinSuccess(false);
                setNewPin('');
                setConfirmPin('');
            }, 2000);
        } else {
            setPinError('Erreur technique lors de la mise ├á jour');
        }
    };

    const handleLogout = async () => {
        const ok = await confirm({
            title: 'Se d├⌐connecter ?',
            message: 'Vous allez ├¬tre d├⌐connect├⌐ de votre profil.',
            confirmLabel: 'Me d├⌐connecter'
        });
        if (ok) {
            logout();
            router.push('/login');
        }
    };

    const handleCloseAccount = () => {
        const text = encodeURIComponent(`DEMANDE DE CL├öTURE DE COMPTE : ${user?.name} (T├⌐l: ${user?.phoneNumber}, R├┤le: ${user?.role}).`);
        window.open(`https://wa.me/2250000000000?text=${text}`, '_blank');
    };

    const [supabaseStatus, setSupabaseStatus] = useState<'LOADING' | 'CONNECTED' | 'DISCONNECTED'>('LOADING');

    useEffect(() => {
        const checkSupabase = async () => {
            try {
                const { error } = await supabase.from('products').select('count', { count: 'exact', head: true });
                if (!error) setSupabaseStatus('CONNECTED');
                else setSupabaseStatus('DISCONNECTED');
            } catch (err) {
                setSupabaseStatus('DISCONNECTED');
            }
        };
        if (isOnline) checkSupabase(); // Changed navigator.onLine to isOnline
        else setSupabaseStatus('DISCONNECTED');
    }, [isOnline]); // Added isOnline to dependency array

    return (
        <main className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-32">
            <SupportCenter
