                                            >
                                                Sauvegarder
                                            </button>
                                        </div>
                                    </div>
                                </>
                            )}
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </main>
    );
}

function ProfileMenuItem({ icon: Icon, label, color, bgColor, actionLabel, onClick }: any) {
    return (
        <button
            onClick={onClick}
            className="w-full bg-white dark:bg-slate-900 p-5 rounded-[28px] border border-slate-100 dark:border-slate-800 flex items-center justify-between group active:scale-[0.98] transition-all shadow-sm"
        >
            <div className="flex items-center gap-4">
                <div className={`bg-slate-50 dark:bg-slate-800 p-3 rounded-2xl ${color}`}>
                    <Icon size={20} />
                </div>
                <div>
                    <span className="font-black text-slate-900 dark:text-white text-xs uppercase tracking-wider">{label}</span>
                </div>
            </div>
            <div className="flex items-center gap-3">
                {actionLabel && <span className="text-[9px] font-black uppercase tracking-widest text-emerald-500 bg-emerald-50 dark:bg-emerald-950/30 px-2 py-1 rounded-md">{actionLabel}</span>}
                <div className="text-slate-300 group-hover:translate-x-1 transition-transform">
                    <ChevronLeft size={18} className="rotate-180" />
                </div>
            </div>
        </button>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Package, AlertCircle, ShoppingCart, Info } from 'lucide-react';
import { BarcodeScanner } from '@/components/BarcodeScanner';
import { useProductContext } from '@/context/ProductContext';
import { useStock } from '@/hooks/useStock';
import { useHistory } from '@/hooks/useHistory';
import { useVoice } from '@/hooks/useVoice';
import { StockDetailModal } from '@/components/StockDetailModal';

export default function ScannerPage() {
    const router = useRouter();
    const { products } = useProductContext();
    const { stock } = useStock();
    const { addTransaction } = useHistory();
    const { speakIfNecessary } = useVoice();

    const [scannedProduct, setScannedProduct] = useState<any>(null);
    const [isScanning, setIsScanning] = useState(true);
    const [scanError, setScanError] = useState('');
    const [showDetails, setShowDetails] = useState(false);

    // Play a beep sound (optional, assuming sound.play() logic or just visual feedback)
    const playScanSound = () => {
        try {
            const audio = new Audio('/beep.mp3'); // Add a short beep sound in public folder if possible
            audio.play().catch(() => { });
        } catch (e) {
            // ignore
        }
    };

    const handleScanSuccess = (decodedText: string) => {
        playScanSound();
        setIsScanning(false);
        setScanError('');

        // Find the product in the local DB
        const foundProduct = products.find(p => p.barcode === decodedText || p.id === decodedText);

        if (foundProduct) {
            setScannedProduct(foundProduct);
            const shortName = foundProduct.audioName.replace(/^[Ll]e\s+/, '').replace(/^[Ll]a\s+/, '').replace(/^[Ll]'\s+/, '');
            speakIfNecessary(`${shortName} trouv├⌐. Prix : ${foundProduct.price} francs.`, 'NORMAL');
        } else {
            setScanError(`Code non reconnu : ${decodedText}`);
            speakIfNecessary("Produit non trouv├⌐ dans le catalogue.", 'HIGH');
        }
    };

    const resetScanner = () => {
        setScannedProduct(null);
        setScanError('');
        setIsScanning(true);
    };

    const handleQuickSell = () => {
        if (!scannedProduct) return;

        const currentStock = stock[scannedProduct.id] || 0;
        if (currentStock <= 0) {
            setScanError("Stock ├⌐puis├⌐ !");
            speakIfNecessary("Attention, ce produit est en rupture de stock.", 'HIGH');
            return;
        }

        // Add to history directly as a sale (simplified flow for scanner)
        addTransaction({
            type: 'VENTE',
            productId: scannedProduct.id,
            productName: scannedProduct.name,
            quantity: 1,
            price: scannedProduct.price
        });

        const shortName = scannedProduct.audioName.replace(/^[Ll]e\s+/, '').replace(/^[Ll]a\s+/, '').replace(/^[Ll]'\s+/, '');
        speakIfNecessary(`Vendu : un ${shortName}.`, 'LOW');

        // Return to scanner after 1.5s
        setTimeout(() => resetScanner(), 1500);
    };

    return (
        <main className="min-h-screen bg-slate-950 text-white flex flex-col fixed inset-0 z-50 overflow-hidden">
            {/* Header / Top Bar */}
            <div className="absolute top-0 left-0 right-0 p-4 md:p-6 flex items-center justify-between z-20 bg-gradient-to-b from-slate-900/80 to-transparent">
                <button
                    onClick={() => router.back()}
                    className="w-12 h-12 bg-white/10 backdrop-blur-md rounded-2xl flex items-center justify-center text-white active:scale-95 transition-all"
                >
                    <ArrowLeft size={24} />
                </button>
                <div className="text-center">
                    <h1 className="text-xl font-black uppercase tracking-tight">Scanner</h1>
                    <p className="text-[10px] font-bold text-amber-500 uppercase tracking-widest">Recherche Rapide</p>
                </div>
                <div className="w-12" /> {/* Spacer */}
            </div>

            {/* Main Content Area */}
            <div className="flex-1 relative flex flex-col">

                {/* Scanner View */}
                <AnimatePresence mode="wait">
                    {isScanning && (
                        <motion.div
                            key="scanner-view"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="absolute inset-0 flex items-center justify-center"
                        >
                            <div className="w-full max-w-md mx-auto aspect-square p-6 md:p-8">
                                <div className="rounded-[40px] overflow-hidden border-4 border-amber-500 shadow-2xl relative">
                                    <BarcodeScanner
                                        onScan={handleScanSuccess}
                                        onClose={() => router.back()}
                                    />
                                    {/* Scanning Line Animation overlay handled within BarcodeScanner now, or add generic one here */}
                                </div>
                                <p className="text-center mt-6 text-sm font-bold text-slate-400 uppercase tracking-widest">Placez le code-barres dans le cadre</p>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>

                {/* Status / Error Message */}
                {scanError && !scannedProduct && (
                    <motion.div
                        initial={{ opacity: 0, y: 50 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="absolute bottom-32 left-4 right-4 md:left-auto md:right-auto md:w-96 md:mx-auto bg-rose-500 text-white p-4 rounded-3xl flex items-start gap-3 shadow-2xl z-20"
                    >
                        <AlertCircle className="shrink-0" />
                        <div>
                            <p className="font-black text-sm uppercase">{scanError}</p>
                            <button onClick={resetScanner} className="text-rose-200 mt-2 text-xs font-bold uppercase underline">R├⌐essayer</button>
                        </div>
                    </motion.div>
                )}

                {/* Results Panel - Wave Style Bottom Sheet */}
                <AnimatePresence>
                    {!isScanning && scannedProduct && (
                        <motion.div
                            key="result-view"
                            initial={{ opacity: 0, y: '100%' }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: '100%' }}
                            transition={{ type: "spring", damping: 30, stiffness: 300 }}
                            className="absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 rounded-t-[40px] p-6 pb-12 shadow-[0_-15px_50px_rgba(0,0,0,0.4)] z-30"
                        >
                            {/* Handle bars style Wave */}
                            <div className="w-12 h-1 bg-slate-200 dark:bg-slate-800 rounded-full mx-auto mb-8" />

                            <div className="flex items-center gap-5 mb-8">
                                <div className="w-20 h-20 bg-slate-50 dark:bg-slate-800 rounded-[28px] flex items-center justify-center shrink-0 shadow-sm border border-slate-100 dark:border-slate-700">
                                    {scannedProduct.imageUrl ? (
                                        <img src={scannedProduct.imageUrl} className="w-full h-full object-contain p-2" alt="" />
                                    ) : (
                                        <Package size={36} className="text-slate-700 dark:text-slate-300" />
                                    )}
                                </div>
                                <div className="flex flex-col gap-1">
                                    <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter leading-tight">
                                        {scannedProduct.name}
                                    </h2>
                                    <p className="text-orange-500 font-black text-2xl tracking-tight">
                                        {scannedProduct.price.toLocaleString()} F
                                    </p>
                                </div>
                            </div>

                            {/* Info Card Stock style Wave */}
                            <div className="bg-slate-50 dark:bg-slate-800/50 p-6 rounded-[32px] mb-8 border border-slate-100 dark:border-slate-700/50">
                                <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-2">En Stock</p>
                                <p className="text-3xl font-black text-emerald-500 leading-none">
                                    {stock[scannedProduct.id] || 0}
                                </p>
                            </div>

                            <div className="flex gap-4 mb-6">
                                <button
                                    onClick={() => setShowDetails(true)}
                                    className="flex-1 py-5 bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white rounded-[24px] font-black uppercase text-xs tracking-[0.15em] active:scale-95 transition-all shadow-sm flex items-center justify-center gap-2"
                                >
                                    <Info size={16} />
                                    D├⌐tails
                                </button>
                                <button
                                    onClick={handleQuickSell}
                                    className="flex-[1.5] py-5 bg-primary text-white rounded-[24px] font-black uppercase text-xs tracking-[0.15em] active:scale-95 transition-all shadow-xl shadow-emerald-500/20 flex items-center justify-center gap-2.5"
                                >
                                    <ShoppingCart size={18} />
                                    Vendre
                                </button>
                            </div>

                            <button
                                onClick={resetScanner}
                                className="w-full text-slate-400 font-bold uppercase text-[10px] tracking-[0.2em] active:opacity-50 transition-opacity"
                            >
                                Scanner un autre produit
                            </button>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Modals */}
            <AnimatePresence>
                {showDetails && scannedProduct && (
                    <StockDetailModal
                        product={scannedProduct}
                        currentStock={stock[scannedProduct.id] || 0}
                        onClose={() => setShowDetails(false)}
                    />
                )}
            </AnimatePresence>
        </main>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Phone, User, CheckCircle2, ChevronRight, ArrowLeft, Lock, AlertCircle, Delete, Camera, MapPin } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';

export default function SignupPage() {
    const router = useRouter();
    const { signup, isAuthenticated, user } = useAuth();

    const [name, setName] = useState('');
    const [phoneNumber, setPhoneNumber] = useState('');
    const [pin, setPin] = useState('');
    const [role, setRole] = useState<'MERCHANT' | 'PRODUCER' | 'COOPERATIVE' | 'FIELD_AGENT'>('MERCHANT');
    const [error, setError] = useState('');
    const [step, setStep] = useState<'IDENTITY' | 'PHOTO' | 'LOCATION' | 'PIN'>('IDENTITY');
    const [photo, setPhoto] = useState<string | null>(null);
    const [location, setLocation] = useState<string>('');

    const getDashboardPath = (role: string | undefined) => {
        switch (role) {
            case 'SUPERVISOR': return '/admin';
            case 'PRODUCER': return '/producteur';
            case 'COOPERATIVE': return '/cooperative';
            case 'FIELD_AGENT': return '/agent';
            case 'MERCHANT':
            default: return '/commercant';
        }
    };

    useEffect(() => {
        if (isAuthenticated && user) {
            router.push(getDashboardPath(user.role));
        }
    }, [isAuthenticated, user, router]);

    // Handle Hardware Back Button for multi-steps
    useEffect(() => {
        const handlePopState = (e: PopStateEvent) => {
            if (step === 'PIN') {
                e.preventDefault();
                setStep('LOCATION');
                window.history.pushState(null, '', window.location.pathname);
            } else if (step === 'LOCATION') {
                e.preventDefault();
                setStep('PHOTO');
                window.history.pushState(null, '', window.location.pathname);
            } else if (step === 'PHOTO') {
                e.preventDefault();
                setStep('IDENTITY');
                window.history.pushState(null, '', window.location.pathname);
            }
        };

        if (step !== 'IDENTITY') {
            window.history.pushState(null, '', window.location.pathname);
            window.addEventListener('popstate', handlePopState);
        }

        return () => window.removeEventListener('popstate', handlePopState);
    }, [step]);

    if (isAuthenticated) return null;

    const handleIdentitySubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (name.length >= 3 && phoneNumber.length >= 8) {
            setStep('PHOTO');
            setError('');
        } else {
            setError('Veuillez remplir correctement tous les champs');
        }
    };

    const handlePinPress = (num: string) => {
        if (pin.length < 4) {
            const newPin = pin + num;
            setPin(newPin);
            if (newPin.length === 4) {
                handleSignup(newPin);
            }
        }
    };

    const handleSignup = async (finalPin: string) => {
        const success = await signup(name, phoneNumber, finalPin, role);
        if (success) {
            // Success handled by useEffect
        } else {
            setError('Ce num├⌐ro est d├⌐j├á utilis├⌐');
            setPin('');
            setStep('IDENTITY');
        }
    };

    return (
        <main className="min-h-screen bg-white dark:bg-slate-950 flex flex-col p-3 items-center justify-center relative overflow-hidden">
            {/* Background Accents */}
            <div className="absolute -top-20 -left-20 w-80 h-80 bg-blue-50 rounded-full blur-3xl opacity-50" />
            <div className="absolute -bottom-20 -right-20 w-80 h-80 bg-emerald-50 rounded-full blur-3xl opacity-50" />

            <div className="w-full max-w-md relative z-10">
                {/* Header */}
                <header className="text-center mb-4 sm:mb-8">
                    <motion.div
                        initial={{ scale: 0.5, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        className="w-14 h-14 sm:w-20 sm:h-20 bg-blue-600 rounded-2xl sm:rounded-[28px] mx-auto mb-3 sm:mb-6 flex items-center justify-center shadow-xl sm:shadow-2xl shadow-blue-100"
                    >
                        <User size={28} className="text-white sm:w-10 sm:h-10" />
                    </motion.div>
                    <h1 className="text-xl sm:text-4xl font-black text-slate-900 dark:text-white uppercase tracking-tighter line-clamp-1 leading-tight">Nouveau Compte</h1>
                    <p className="text-slate-400 font-bold uppercase tracking-widest text-[8px] sm:text-[10px] mt-1 sm:mt-2">Rejoignez l'├⌐cosyst├¿me marchand</p>
                </header>

                <AnimatePresence mode="wait">
                    {step === 'IDENTITY' ? (
                        <motion.form
                            key="id-step"
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 20 }}
                            onSubmit={handleIdentitySubmit}
                            className="space-y-4 sm:space-y-6"
                        >
                            <div className="space-y-1 sm:space-y-2">
                                <label className="text-[9px] font-black uppercase tracking-[0.3em] text-slate-400 ml-5 mb-1 block">Votre Nom</label>
                                <div className="relative">
                                    <User className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                                    <input
                                        autoFocus
                                        type="text"
                                        placeholder="Ton nom"
                                        value={name}
                                        onChange={e => setName(e.target.value)}
                                        className="w-full bg-slate-50 dark:bg-slate-900 border-[3px] border-slate-100 dark:border-slate-800 rounded-[24px] sm:rounded-[32px] p-3.5 sm:p-5 pl-11 sm:pl-14 font-black text-lg sm:text-xl text-slate-900 dark:text-white outline-none focus:border-blue-500 transition-all uppercase tracking-tight"
                                    />
                                </div>
                            </div>

                            <div className="space-y-1 sm:space-y-2">
                                <label className="text-[9px] font-black uppercase tracking-[0.3em] text-slate-400 ml-5 mb-1 block">Num├⌐ro de T├⌐l├⌐phone</label>
                                <div className="relative">
                                    <Phone className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                                    <input
                                        type="tel"
                                        placeholder="0102030405"
                                        value={phoneNumber}
                                        onChange={e => setPhoneNumber(e.target.value)}
                                        className="w-full bg-slate-50 dark:bg-slate-900 border-[3px] border-slate-100 dark:border-slate-800 rounded-[24px] sm:rounded-[32px] p-3.5 sm:p-5 pl-11 sm:pl-14 font-black text-lg sm:text-xl text-slate-900 dark:text-white outline-none focus:border-blue-500 transition-all uppercase tracking-tight"
                                    />
                                </div>
                            </div>

                            <div className="space-y-1 sm:space-y-2">
                                <label className="text-[9px] sm:text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 ml-5 sm:ml-6 mb-1 block">Votre R├┤le</label>
                                <div className="grid grid-cols-2 gap-2 sm:gap-3">
                                    {(['MERCHANT', 'PRODUCER', 'COOPERATIVE', 'FIELD_AGENT'] as const).map(r => (
                                        <button
                                            key={r}
                                            type="button"
                                            onClick={() => setRole(r)}
                                            className={`p-3 sm:p-4 rounded-xl sm:rounded-2xl border-2 font-black text-[10px] sm:text-xs transition-all ${role === r ? 'bg-blue-600 border-blue-600 text-white shadow-lg active:scale-95' : 'bg-white dark:bg-slate-900 border-slate-100 dark:border-slate-800 text-slate-500 hover:border-blue-200'}`}
                                        >
                                            {r === 'MERCHANT' ? 'Commer├ºant' :
                                                r === 'PRODUCER' ? 'Producteur' :
                                                    r === 'COOPERATIVE' ? 'Coop├⌐rative' : 'Agent'}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {error && (
                                <div className="flex items-center gap-3 bg-rose-50 p-4 rounded-2xl text-rose-600 font-bold text-sm">
                                    <AlertCircle size={20} /> {error}
                                </div>
                            )}

                            <button
                                type="submit"
                                className="w-full bg-slate-900 dark:bg-blue-600 text-white p-4 sm:p-6 rounded-[24px] sm:rounded-[32px] font-black uppercase tracking-[0.2em] text-[10px] sm:text-sm shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3"
                            >
                                Cr├⌐er mon PIN <ChevronRight size={16} className="sm:w-5 sm:h-5" />
                            </button>

                            <button
                                type="button"
                                onClick={() => router.push('/login')}
                                className="w-full py-1.5 sm:py-4 text-slate-400 font-black uppercase text-[8px] sm:text-[10px] tracking-widest hover:text-blue-600 transition-colors"
                            >
                                J'ai d├⌐j├á un compte
                            </button>
                        </motion.form>
                    ) : step === 'PHOTO' ? (
                        <motion.div
                            key="photo-step"
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 20 }}
                            className="space-y-8 text-center"
                        >
                            <h2 className="text-xl sm:text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Photo de profil</h2>
                            <p className="text-xs sm:text-sm font-bold text-slate-400">Pour s├⌐curiser votre compte et renforcer la confiance.</p>

                            <div
                                onClick={() => setPhoto('captured')}
                                className={`w-36 h-36 sm:w-40 sm:h-40 mx-auto rounded-[32px] sm:rounded-[40px] border-[3px] sm:border-4 flex flex-col items-center justify-center cursor-pointer transition-all ${photo ? 'bg-emerald-50 border-emerald-500 text-emerald-500' : 'bg-slate-50 border-slate-200 text-slate-400 dark:bg-slate-900 dark:border-slate-800 dark:text-slate-500'}`}
                            >
                                {photo ? <CheckCircle2 size={40} /> : <Camera size={40} />}
                                <span className="text-[10px] sm:text-xs font-black uppercase mt-2">{photo ? 'Photo OK' : 'Prendre une photo'}</span>
                            </div>

                            <button
                                onClick={() => setStep('LOCATION')}
                                disabled={!photo}
                                className="w-full bg-slate-900 dark:bg-blue-600 disabled:bg-slate-200 disabled:text-slate-400 text-white p-6 rounded-[32px] font-black uppercase tracking-[0.2em] text-sm shadow-2xl active:scale-95 transition-all"
                            >
                                Continuer
                            </button>
                            <button
                                onClick={() => setStep('IDENTITY')}
                                className="w-full py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-blue-600 transition-colors"
                            >
                                Retour
                            </button>
                        </motion.div>
                    ) : step === 'LOCATION' ? (
                        <motion.div
                            key="location-step"
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 20 }}
                            className="space-y-8 text-center"
                        >
                            <h2 className="text-xl sm:text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Emplacement</h2>
                            <p className="text-xs sm:text-sm font-bold text-slate-400">O├╣ se trouve votre activit├⌐ ?</p>

                            <div
                                onClick={() => {
                                    setLocation('G├⌐olocalisation r├⌐ussie');
                                }}
                                className={`w-36 h-36 sm:w-40 sm:h-40 mx-auto rounded-[32px] sm:rounded-[40px] border-[3px] sm:border-4 flex flex-col items-center justify-center cursor-pointer transition-all ${location ? 'bg-emerald-50 border-emerald-500 text-emerald-500' : 'bg-slate-50 border-slate-200 text-slate-400 dark:bg-slate-900 dark:border-slate-800 dark:text-slate-500'}`}
                            >
                                {location ? <CheckCircle2 size={40} /> : <MapPin size={40} />}
                                <span className="text-[10px] sm:text-xs font-black uppercase mt-2 text-center px-4">{location || 'Me g├⌐olocaliser'}</span>
                            </div>

                            <button
                                onClick={() => setStep('PIN')}
                                disabled={!location}
                                className="w-full bg-slate-900 dark:bg-blue-600 disabled:bg-slate-200 disabled:text-slate-400 text-white p-6 rounded-[32px] font-black uppercase tracking-[0.2em] text-sm shadow-2xl active:scale-95 transition-all"
                            >
                                Cr├⌐er mon PIN
                            </button>
                            <button
                                onClick={() => setStep('PHOTO')}
                                className="w-full py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-blue-600 transition-colors"
                            >
                                Retour
                            </button>
                        </motion.div>
                    ) : (
                        <motion.div
                            key="pin-setup"
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.9 }}
                            className="flex flex-col items-center w-full"
                        >
                            <label className="text-[9px] sm:text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 mb-6 sm:mb-8 text-center uppercase">D├⌐finissez votre PIN secret (4 chiffres)</label>

                            {/* PIN Dots */}
                            <div className="flex gap-4 sm:gap-6 mb-8 sm:mb-12">
                                {[0, 1, 2, 3].map(i => (
                                    <div
                                        key={i}
                                        className={`w-4 h-4 sm:w-6 sm:h-6 rounded-full border-[3px] sm:border-4 transition-all duration-100 ${pin.length > i ? 'bg-blue-600 border-blue-600 scale-125' : 'bg-transparent border-slate-200'}`}
                                    />
                                ))}
                            </div>

                            {/* Wave Pad */}
                            <div className="grid grid-cols-3 gap-3 sm:gap-6 w-full max-w-[280px] sm:max-w-[320px]">
                                {[1, 2, 3, 4, 5, 6, 7, 8, 9, 'BACK', 0, 'DEL'].map(val => (
                                    <React.Fragment key={val}>
                                        {val === 'BACK' ? (
                                            <button
                                                onClick={() => setStep('LOCATION')}
                                                className="aspect-square flex items-center justify-center text-slate-300 hover:text-rose-500 transition-colors"
                                            >
                                                <ArrowLeft size={24} className="sm:w-8 sm:h-8" />
                                            </button>
                                        ) : val === 'DEL' ? (
                                            <button
                                                onClick={() => setPin(prev => prev.slice(0, -1))}
                                                className="aspect-square flex items-center justify-center text-slate-300 hover:text-slate-900 transition-colors"
                                            >
                                                <Delete size={24} className="sm:w-8 sm:h-8" />
                                            </button>
                                        ) : (
                                            <button
                                                onClick={() => handlePinPress(val.toString())}
                                                className="aspect-square bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-[18px] sm:rounded-[24px] flex items-center justify-center text-2xl sm:text-3xl font-black text-slate-900 dark:text-white shadow-sm sm:shadow-lg active:scale-90 active:bg-blue-50 transition-all"
                                            >
                                                {val}
                                            </button>
                                        )}
                                    </React.Fragment>
                                ))}
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </main>
    );
}

'use client';

import React, { useEffect } from 'react';
import { motion } from 'framer-motion';
import {
    ChevronLeft,
    Clock,
    ShoppingBag,
    PlusCircle,
    MinusCircle,
    Volume2,
    TrendingUp,
    Package,
    ArrowLeft
} from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useVoice } from '@/hooks/useVoice';
import { useHistory } from '@/hooks/useHistory';
import { useAuth } from '@/context/AuthContext';
import { useProductContext } from '@/context/ProductContext';
import { useStock } from '@/hooks/useStock';

export default function StockDetailPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = React.use(params);
    const router = useRouter();
    const { products } = useProductContext();
    const { stock } = useStock();
    const { speakIfNecessary } = useVoice();
    const { getProductHistory } = useHistory();
    const { user } = useAuth();

    const product = products.find(p => p.id.toString() === id);
    const currentStock = product ? (stock[product.id] || 0) : 0;

    const name = user?.name?.split(' ')[0] || 'Marchand';
    const capitalValue = product ? (currentStock * product.price) : 0;
    const productHistory = product ? getProductHistory(product.id).slice(0, 5) : [];

    useEffect(() => {
        if (product) {
            speakIfNecessary(`D├⌐tails de ${product.name}. Ton stock actuel est de ${currentStock}.`, 'NORMAL', true);
        }
    }, [product]);

    if (!product) {
        return (
            <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex flex-col items-center justify-center p-6 text-center">
                <Package size={64} className="text-slate-300 mb-4" />
                <h2 className="text-xl font-bold text-slate-800 dark:text-white uppercase mb-4">Produit introuvable</h2>
                <button
                    onClick={() => router.push('/stock')}
                    className="px-8 py-3 bg-primary text-white rounded-2xl font-bold uppercase tracking-widest shadow-lg active:scale-95 transition-transform"
                >
                    Retour au stock
                </button>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-32">
            {/* Header Color├⌐ (Card Overlap Style) */}
            <div className={`pt-8 pb-32 px-4 rounded-b-[2.5rem] relative shadow-lg ${product.color.split(' ')[0] === 'bg-white' ? 'bg-primary' : product.color.split(' ')[0]}`}>
                <div className="flex justify-between items-center max-w-lg mx-auto mb-6">
                    <button
                        onClick={() => router.back()}
                        className="w-10 h-10 bg-white text-slate-900 rounded-full flex items-center justify-center active:scale-95 transition-transform shadow-sm"
                    >
                        <ArrowLeft size={20} />
                    </button>
                    <div className="text-center flex-1 pr-10">
                        <h1 className="text-slate-900 font-black text-lg tracking-wide uppercase truncate px-2">{product.name}</h1>
                        <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-0.5">D├⌐tails du Stock</p>
                    </div>
                </div>
            </div>

            {/* Main Content Overlap */}
            <main className="mt-[-60px] relative z-10 px-4 max-w-lg mx-auto space-y-4">
                {/* Product Stats Card */}
                <div className="bg-white dark:bg-slate-900 rounded-[32px] p-6 shadow-xl border border-slate-100 dark:border-slate-800">
                    <div className="flex items-center gap-5 mb-8">
                        <div className={`p-4 rounded-[24px] bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 ${product.iconColor} shrink-0`}>
                            <product.icon size={40} />
                        </div>
                        <div className="flex-1 min-w-0">
                            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Stock Actuel</span>
                            <div className="flex items-end gap-2">
                                <span className="text-5xl font-black text-slate-900 dark:text-white leading-none tracking-tighter">{currentStock}</span>
                                <span className="text-sm font-bold text-slate-400 uppercase tracking-widest pb-1">Unit├⌐s</span>
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="bg-slate-50 dark:bg-slate-800/50 p-5 rounded-3xl border border-slate-100 dark:border-slate-700/50 text-center">
                            <span className="text-[10px] font-bold text-slate-400 uppercase block mb-1 tracking-widest">Prix Unit├⌐</span>
                            <span className="text-xl font-black text-slate-900 dark:text-white">{product.price.toLocaleString()} F</span>
                        </div>
                        <div className="bg-emerald-50 dark:bg-emerald-900/10 p-5 rounded-3xl border border-emerald-100 dark:border-emerald-800/50 text-center">
                            <span className="text-[10px] font-bold text-emerald-600 dark:text-emerald-400 uppercase block mb-1 tracking-widest">Valeur Stock</span>
                            <span className="text-xl font-black text-emerald-700 dark:text-emerald-300">{capitalValue.toLocaleString()} F</span>
                        </div>
                    </div>
                </div>

                {/* Voice Interaction */}
                <motion.div
                    whileTap={{ scale: 0.98 }}
                    onClick={() => speakIfNecessary(`Ce produit repr├⌐sente ${capitalValue} francs de ton capital marchand actuel, ${name}.`, 'NORMAL', true)}
                    className="bg-primary p-5 rounded-[24px] flex items-center gap-4 text-white shadow-lg cursor-pointer"
                >
                    <div className="bg-white/20 p-2.5 rounded-xl">
                        <Volume2 size={24} />
                    </div>
                    <p className="font-bold text-xs leading-tight uppercase tracking-wider">
                        ├ëcouter l'analyse de l'assistant sur ce produit
                    </p>
                </motion.div>

                {/* History Section */}
                <div className="bg-white dark:bg-slate-900 rounded-[32px] p-6 shadow-sm border border-slate-100 dark:border-slate-800">
                    <div className="flex items-center justify-between mb-6">
