                        </div>
                        <div className="w-1.5 h-1.5 rounded-full bg-slate-200" />
                    </div>

                    <div className="space-y-3">
                        {productHistory.length === 0 ? (
                            <div className="py-10 text-center">
                                <p className="text-xs font-bold text-slate-300 uppercase tracking-widest italic">Aucun mouvement</p>
                            </div>
                        ) : (
                            productHistory.map((t, idx) => (
                                <div key={idx} className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800/30 rounded-2xl border border-slate-100 dark:border-slate-700/30">
                                    <div className="flex items-center gap-4 min-w-0 pr-2">
                                        <div className={`p-2.5 rounded-xl shrink-0 ${t.type === 'VENTE' ? 'bg-emerald-100 text-emerald-600' :
                                            t.type === 'LIVRAISON' ? 'bg-blue-100 text-blue-600' :
                                                'bg-rose-100 text-rose-600'
                                            }`}>
                                            {t.type === 'VENTE' ? <ShoppingBag size={18} /> :
                                                t.type === 'LIVRAISON' ? <PlusCircle size={18} /> :
                                                    <MinusCircle size={18} />}
                                        </div>
                                        <div className="min-w-0">
                                            <p className="font-black text-slate-800 dark:text-white text-xs leading-none uppercase tracking-wider truncate mb-1">{t.type}</p>
                                            <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest truncate">{new Date(t.timestamp).toLocaleDateString()} ΓÇó {t.quantity} unit├⌐(s)</p>
                                        </div>
                                    </div>
                                    <p className="font-black text-xs text-slate-900 dark:text-white shrink-0 whitespace-nowrap">
                                        {t.type === 'VENTE' ? '+' : '-'}{t.price.toLocaleString()} F
                                    </p>
                                </div>
                            ))
                        )}
                    </div>
                </div>

                {/* Performance Hint */}
                <div className="bg-amber-50 dark:bg-amber-900/10 p-5 rounded-[24px] border border-amber-100 dark:border-amber-900/20 flex items-start gap-4">
                    <div className="bg-amber-100 dark:bg-amber-800 p-2 rounded-xl shrink-0">
                        <TrendingUp size={20} className="text-amber-600 dark:text-amber-400" />
                    </div>
                    <div>
                        <h4 className="font-black text-[10px] text-amber-700 dark:text-amber-400 uppercase tracking-widest mb-1">Performance</h4>
                        <p className="text-[10px] font-bold text-amber-600 dark:text-amber-500/80 leading-snug">
                            Ce produit est dans ton Top 5 des ventes ce mois-ci. Pense ├á commander du stock demain.
                        </p>
                    </div>
                </div>
            </main>
        </div>
    );
}

'use client';

import React, { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Save, Package, CreditCard, Barcode, Camera, X, CheckCircle2 } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { BarcodeScanner } from '@/components/BarcodeScanner';
import { useProductContext } from '@/context/ProductContext';
import { useAssistant } from '@/hooks/useAssistant';

export default function AddProductPage() {
    const router = useRouter();
    const { addProduct } = useProductContext();
    const { speakIfNecessary } = useAssistant();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [name, setName] = useState('');
    const [price, setPrice] = useState('');
    const [barcode, setBarcode] = useState('');
    const [imageUrl, setImageUrl] = useState('');
    const [isScanning, setIsScanning] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [showSuccess, setShowSuccess] = useState(false);

    const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setImageUrl(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!name || !price) return;

        setIsSaving(true);
        try {
            await addProduct({
                name: name.toUpperCase(),
                price: parseInt(price),
                barcode: barcode || undefined,
                imageUrl: imageUrl || undefined,
                color: 'bg-slate-50',
                iconColor: 'text-slate-600',
                audioName: name.toLowerCase(),
                icon: Package
            });
            speakIfNecessary(`${name} a ├⌐t├⌐ ajout├⌐ ├á votre catalogue.`, 'LOW');

            // R├⌐initialiser le formulaire
            setName('');
            setPrice('');
            setBarcode('');
            setImageUrl('');

            // Afficher le toast
            setShowSuccess(true);
            setTimeout(() => setShowSuccess(false), 3000);
        } catch (error) {
            console.error("Erreur, impossible d'ajouter", error);
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-32">
            <AnimatePresence>
                {showSuccess && (
                    <motion.div
                        initial={{ opacity: 0, y: -50 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -50 }}
                        className="fixed top-4 left-4 right-4 z-50 bg-emerald-500 text-white p-4 rounded-2xl shadow-xl flex items-center justify-center gap-3"
                    >
                        <CheckCircle2 size={24} />
                        <span className="font-bold text-sm uppercase tracking-widest">Produit ajout├⌐ !</span>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Header Color├⌐ (Card Overlap Style) */}
            <div className="bg-primary pt-8 pb-32 px-4 rounded-b-[2.5rem] relative shadow-lg">
                <div className="flex items-center gap-4 max-w-lg mx-auto mb-6">
                    <button onClick={() => router.back()} className="w-10 h-10 bg-white text-primary rounded-full flex items-center justify-center active:scale-95 transition-transform shadow-sm">
                        <ChevronLeft size={20} />
                    </button>
                    <div className="flex-1">
                        <h1 className="text-white font-bold text-lg tracking-wide uppercase">Nouveau Produit</h1>
                        <p className="text-emerald-200 text-[10px] font-bold uppercase tracking-widest mt-0.5">Ajout au catalogue</p>
                    </div>
                </div>
            </div>

            {/* Main Content Overlap */}
            <main className="mt-[-60px] relative z-10 px-4 max-w-lg mx-auto">
                <div className="bg-white dark:bg-slate-900 rounded-[28px] p-6 shadow-xl border border-slate-100 dark:border-slate-800">
                    <form onSubmit={handleSubmit} className="space-y-6">
                        {/* Photo du Produit */}
                        <div className="space-y-2">
                            <label className="text-[10px] font-bold uppercase tracking-wider text-slate-400 ml-2 block">Photo du Produit</label>
                            <div className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-2xl bg-slate-50 dark:bg-slate-800/50">
                                <input
                                    type="file"
                                    accept="image/*"
                                    capture="environment"
                                    ref={fileInputRef}
                                    onChange={handlePhotoCapture}
                                    className="hidden"
                                />
                                {imageUrl ? (
                                    <div className="relative w-32 h-32 rounded-xl overflow-hidden shadow-md">
                                        <img src={imageUrl} alt="Aper├ºu" className="w-full h-full object-cover" />
                                        <button
                                            type="button"
                                            onClick={() => setImageUrl('')}
                                            className="absolute top-2 right-2 w-8 h-8 bg-black/50 text-white rounded-full flex items-center justify-center backdrop-blur-sm"
                                        >
                                            <X size={16} />
                                        </button>
                                    </div>
                                ) : (
                                    <button
                                        type="button"
                                        onClick={() => fileInputRef.current?.click()}
                                        className="w-20 h-20 bg-white dark:bg-slate-700 rounded-full flex items-center justify-center text-slate-400 shadow-sm active:scale-95 transition-all"
                                    >
                                        <Camera size={32} />
                                    </button>
                                )}
                                <p className="text-[10px] font-bold text-slate-400 mt-4 uppercase tracking-widest text-center">
                                    {imageUrl ? 'Appuyez sur la croix pour changer' : 'Appuyez pour photographier'}
                                </p>
                            </div>
                        </div>

                        {/* Informations Textuelles */}
                        <div className="space-y-4">
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold uppercase tracking-wider text-slate-400 ml-2 block">Nom du Produit</label>
                                <div className="relative">
                                    <Package className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 w-5 h-5" />
                                    <input
                                        type="text"
                                        placeholder="Ex: Savon de Marseille"
                                        value={name}
                                        onChange={e => setName(e.target.value)}
                                        className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-50 dark:border-slate-800 rounded-xl py-4 pr-4 pl-12 font-semibold text-base text-slate-900 dark:text-white outline-none focus:border-primary transition-all placeholder:text-slate-300"
                                        required
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-[10px] font-bold uppercase tracking-wider text-slate-400 ml-2 block">Prix de Vente (FCFA)</label>
                                <div className="relative">
                                    <CreditCard className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 w-5 h-5" />
                                    <input
                                        type="number"
                                        placeholder="0"
                                        value={price}
                                        onChange={e => setPrice(e.target.value)}
                                        className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-50 dark:border-slate-800 rounded-xl py-4 pr-4 pl-12 font-semibold text-base text-slate-900 dark:text-white outline-none focus:border-primary transition-all placeholder:text-slate-300"
                                        required
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-[10px] font-bold uppercase tracking-wider text-slate-400 ml-2 block">Code-Barres</label>
                                <div className="relative flex gap-2">
                                    <div className="relative flex-1">
                                        <Barcode className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 w-5 h-5" />
                                        <input
                                            type="text"
                                            placeholder="Optionnel"
                                            value={barcode}
                                            onChange={e => setBarcode(e.target.value)}
                                            className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-50 dark:border-slate-800 rounded-xl py-4 pr-4 pl-12 font-semibold text-base text-slate-900 dark:text-white outline-none focus:border-primary transition-all placeholder:text-slate-300"
                                        />
                                    </div>
                                    <button
                                        type="button"
                                        onClick={() => setIsScanning(true)}
                                        className="w-14 bg-slate-900 text-white rounded-xl flex items-center justify-center shadow-md active:scale-95 transition-all"
                                    >
                                        <Barcode size={20} />
                                    </button>
                                </div>
                            </div>
                        </div>

                        <button
                            type="submit"
                            disabled={isSaving}
                            className={`w-full ${isSaving ? 'bg-slate-400' : 'bg-primary'} text-white py-5 rounded-2xl font-bold uppercase tracking-wider text-sm shadow-lg active:scale-[0.98] transition-all mt-8 flex items-center justify-center gap-2`}
                        >
                            {isSaving ? 'Enregistrement...' : <><Save size={20} /> Enregistrer ce produit</>}
                        </button>
                    </form>
                </div>
            </main>

            <AnimatePresence>
                {isScanning && (
                    <BarcodeScanner
                        onScan={(code) => {
                            setBarcode(code);
                            setIsScanning(false);
                        }}
                        onClose={() => setIsScanning(false)}
                    />
                )}
            </AnimatePresence>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { ChevronLeft, Package, AlertTriangle, Volume2, Mic, PlusCircle, LayoutGrid, Wheat, CupSoda, Sparkles, MoreHorizontal, Minus, Plus, Eye } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useStock } from '@/hooks/useStock';
import { useProductContext } from '@/context/ProductContext';
import { useAuth } from '@/context/AuthContext';

export default function StockPage() {
    const router = useRouter();
    const { user } = useAuth();
    const { products } = useProductContext();
    const { stock, updateStock } = useStock();
    const [activeCategory, setActiveCategory] = useState('TOUS');

    const categories = [
        { id: 'TOUS', label: 'Tous', icon: LayoutGrid },
        { id: 'VIVRES', label: 'Vivres', icon: Wheat },
        { id: 'BOISSON', label: 'Boisson', icon: CupSoda },
        { id: 'ENTRETIEN', label: 'Entretien', icon: Sparkles },
        { id: 'AUTRE', label: 'Autre', icon: MoreHorizontal },
    ];

    const filteredProducts = activeCategory === 'TOUS'
        ? products
        : products.filter(p => {
            // Priorit├⌐ 1: Utiliser la cat├⌐gorie stricte si elle est d├⌐finie
            if (p.category && p.category !== 'OTHER' && p.category !== '') {
                return p.category === activeCategory;
            }

            // Priorit├⌐ 2: Fallback textuel pour les produits legacy
            const name = p.name.toUpperCase();
            const isVivres = name.includes('RIZ') || name.includes('HUILE') || name.includes('LAIT') || name.includes('ATTI├ëK├ë') || name.includes('PAIN') || name.includes('SUCRE') || name.includes('VIVRE') || name.includes('MAGGI') || name.includes('TOMATE') || name.includes('OIGNON');
            const isBoisson = name.includes('EAU') || name.includes('CAF├ë') || name.includes('JUS') || name.includes('BOISSON') || name.includes('BI├êRE') || name.includes('VIN') || name.includes('SUCRERIE') || name.includes('SODA');
            const isEntretien = name.includes('SAVON') || name.includes('JAVEL') || name.includes('PAPIER') || name.includes('ENTRETIEN') || name.includes('LESSIVE') || name.includes('OMO') || name.includes('├ëPONGE');

            if (activeCategory === 'VIVRES') return isVivres;
            if (activeCategory === 'BOISSON') return isBoisson;
            if (activeCategory === 'ENTRETIEN') return isEntretien;
            if (activeCategory === 'AUTRE') return !isVivres && !isBoisson && !isEntretien;

            return false;
        });

    const lowStockCount = products.filter(p => (stock[p.id] || 0) < 5).length;

    const [isUpdating, setIsUpdating] = useState<string | null>(null);

    const handleUpdateStock = async (productId: string, amount: number) => {
        if (isUpdating) return;
        setIsUpdating(productId);
        try {
            await updateStock(productId, amount);
        } finally {
            // Petit d├⌐lai pour laisser le re-render se faire proprement
            setTimeout(() => setIsUpdating(null), 100);
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-32">
            {/* Header Color├⌐ (Card Overlap Style) */}
            <div className="bg-primary pt-8 pb-32 px-4 rounded-b-[2.5rem] relative shadow-lg">
                <div className="flex justify-between items-center mb-6 max-w-lg mx-auto">
                    <button
                        type="button"
                        onClick={() => router.push('/commercant')}
                        className="w-10 h-10 bg-white text-primary rounded-full flex items-center justify-center active:scale-95 transition-transform shadow-sm"
                    >
                        <ChevronLeft size={20} />
                    </button>
                    <div className="text-center">
                        <h1 className="text-white font-bold text-lg tracking-wide uppercase">Mon Stock</h1>
                        <p className="text-emerald-200 text-[10px] font-bold uppercase tracking-widest mt-0.5">├ëtat des r├⌐serves</p>
                    </div>
                    <div className="w-10 h-10" /> {/* Spacer */}
                </div>

                {/* Bouton Ajouter (Centr├⌐ dans le header) */}
                <div className="flex justify-center max-w-lg mx-auto mt-6">
                    <button
                        type="button"
                        onClick={() => router.push('/stock/ajouter')}
                        className="bg-white text-primary px-8 py-3.5 rounded-full font-bold text-sm uppercase tracking-widest flex items-center gap-2 shadow-md active:scale-95 transition-transform"
                    >
                        <PlusCircle size={18} />
                        Ajouter un produit
                    </button>
                </div>
            </div>

            {/* Main Content Overlap */}
            <main className="mt-[-40px] relative z-10 px-4 max-w-lg mx-auto space-y-6">

                {/* Alerte Stock Bas */}
                {lowStockCount > 0 && (
                    <div className="bg-red-50 dark:bg-red-900/10 border md:border-2 border-red-500 p-2 md:p-4 rounded-xl md:rounded-2xl mb-3 flex items-center gap-2 md:gap-3 text-red-700 dark:text-red-400 shadow-md shadow-red-200 dark:shadow-none">
                        <div className="bg-red-500 p-1.5 md:p-2 rounded-lg text-white shrink-0">
                            <AlertTriangle size={16} className="md:w-6 md:h-6" />
                        </div>
                        <div>
                            <h2 className="font-black uppercase text-xs md:text-sm leading-none">Attention !</h2>
                            <p className="font-bold text-[9px] md:text-xs">{lowStockCount} produit(s) bient├┤t fini(s).</p>
                        </div>
                    </div>
                )}

                {/* Filtres Cat├⌐gories */}
                <div className="bg-white dark:bg-slate-900 rounded-3xl p-4 shadow-xl border border-slate-100 dark:border-slate-800 mb-6">
                    <div className="flex flex-wrap justify-between gap-y-3 gap-x-1">
                        {categories.map(cat => (
                            <button
                                key={cat.id}
                                type="button"
                                onClick={() => setActiveCategory(cat.id)}
                                className={`flex flex-col items-center justify-center gap-1 p-2 w-14 h-16 rounded-[20px] transition-all border ${activeCategory === cat.id ? 'bg-primary border-primary text-white shadow-md scale-105' : 'bg-slate-50 dark:bg-slate-800 border-transparent text-slate-400 hover:border-slate-200'} active:scale-95`}
                            >
                                <cat.icon size={20} strokeWidth={activeCategory === cat.id ? 2.5 : 2} />
                                <span className="font-bold text-[8px] uppercase tracking-widest truncate w-full text-center px-0.5">{cat.label}</span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Liste des items de stock */}
                <div className="grid grid-cols-1 gap-4">
                    {filteredProducts.map((product) => {
                        const qty = stock[product.id] || 0;
                        const isLow = qty < 5;
                        const updating = isUpdating === product.id;
                        return (
                            <div
                                key={product.id}
                                className="bg-white dark:bg-slate-900 rounded-2xl p-5 shadow-sm border border-slate-100 dark:border-slate-800 flex items-center justify-between"
                            >
                                <div className="flex items-center gap-5 min-w-0">
                                    <div className={`w-14 h-14 rounded-xl ${product.imageUrl ? 'bg-slate-100' : product.color} flex items-center justify-center shrink-0 border border-slate-50 overflow-hidden relative`}>
                                        {product.imageUrl ? (
                                            <img src={product.imageUrl} alt={product.name} className="w-full h-full object-cover" />
                                        ) : (
                                            <product.icon className={product.iconColor} size={28} />
                                        )}
                                    </div>
                                    <div className="flex flex-col min-w-0">
                                        <h3 className="font-bold text-slate-800 dark:text-white text-xs uppercase tracking-wider truncate mb-1">{product.name}</h3>
                                        <div className="flex items-baseline gap-2">
                                            <span className={`text-2xl font-bold ${isLow ? 'text-rose-500' : 'text-slate-900 dark:text-white'}`}>
                                                {qty}
                                            </span>
                                            <span className="text-[10px] font-bold text-slate-400">UNIT├ëS</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="flex items-center gap-2 shrink-0">
                                    <button
                                        type="button"
                                        disabled={updating}
                                        onClick={() => handleUpdateStock(product.id, -1)}
                                        className="w-10 h-10 bg-slate-50 dark:bg-slate-800 rounded-xl flex items-center justify-center text-slate-400 hover:text-rose-500 transition-colors active:scale-90 disabled:opacity-50"
                                    >
                                        <Minus size={18} />
                                    </button>
                                    <button
                                        type="button"
                                        disabled={updating}
                                        onClick={() => handleUpdateStock(product.id, 1)}
                                        className="w-10 h-10 bg-slate-50 dark:bg-slate-800 rounded-xl flex items-center justify-center text-slate-400 hover:text-emerald-500 transition-colors active:scale-90 disabled:opacity-50"
                                    >
                                        <Plus size={18} />
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => router.push(`/stock/${product.id}`)}
                                        className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center shadow-lg active:bg-slate-800 transition-colors active:scale-90"
                                    >
                                        <Eye size={18} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Aide */}
                <div className="mt-6 bg-white dark:bg-slate-900 p-3 md:p-4 rounded-[20px] md:rounded-[24px] border border-slate-100 dark:border-slate-800 flex items-center gap-2 md:gap-4 shadow-sm mb-16 md:mb-20">
                    <div className="w-8 h-8 md:w-10 md:h-10 bg-slate-900 rounded-full flex items-center justify-center text-white shrink-0">
                        <Package size={16} className="md:w-5 md:h-5" />
                    </div>
                    <p className="font-bold text-slate-600 dark:text-slate-300 leading-tight text-[10px] md:text-xs">
                        Utilise les boutons + et - pour ajuster ton stock.
                    </p>
                </div>

            </main>
        </div>
    );
}

