'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, TrendingUp, Wallet, ShoppingBag, AlertCircle, Volume2, Mic, CheckCircle2 } from 'lucide-react';
import { useVoice } from '@/hooks/useVoice';
import { useHistory } from '@/hooks/useHistory';
import { useStock } from '@/hooks/useStock';
import { useProductContext } from '@/context/ProductContext';
import { useAuth } from '@/context/AuthContext';

interface AdviceModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export default function AdviceModal({ isOpen, onClose }: AdviceModalProps) {
    const { user } = useAuth();
    const { speakIfNecessary } = useVoice();
    const { history, balance } = useHistory();
    const { stock } = useStock();
    const { products } = useProductContext();
    const [advice, setAdvice] = useState<{ text: string; voice: string; type: 'SUCCESS' | 'WARNING' | 'INFO'; title: string } | null>(null);

    const generateAdvice = () => {
        const name = user?.name?.split(' ')[0] || 'Marchand';
        const advicesLine = [
            { title: "G├⌐rer le Stock", text: "Tes ventes de riz augmentent. Pense ├á commander plus de stock pour ne pas en manquer.", voice: `"${name}, tes ventes de riz augmentent. Pense ├á commander plus de stock pour ne pas en manquer."`, type: 'INFO' as const },
            { title: "Nouveaux Produits", text: "Beaucoup de clients demandent du savon. C'est le moment d'en proposer plus.", voice: `"${name}, beaucoup de clients demandent du savon. C'est le moment d'en proposer plus."`, type: 'INFO' as const },
            { title: "Bonne Gestion", text: "Tu as r├⌐duit tes dettes de 15% cette semaine. Excellent travail !", voice: `"${name}, tu as r├⌐duit tes dettes de 15% cette semaine. Excellent travail !"`, type: 'SUCCESS' as const },
            { title: "Opportunit├⌐", text: "Le march├⌐ central baisse ses prix sur l'huile. Profites-en pour ton stock.", voice: `"${name}, le march├⌐ central baisse ses prix sur l'huile. Profites-en pour ton stock."`, type: 'INFO' as const }
        ];

        // Logic for financial advice
        const stockValue = products.reduce((acc, p) => acc + (p.price * (stock[p.id] || 0)), 0);
        const totalPriceDette = history.filter(t => t.status === 'DETTE').reduce((acc, t) => acc + t.price, 0);
        const totalAssets = balance + stockValue + totalPriceDette;

        // Low stock check
        const lowStock = products.filter(p => (stock[p.id] || 0) < 5);

        // Debt ratio check
        const debtRatio = totalAssets > 0 ? (totalPriceDette / totalAssets) : 0;

        if (debtRatio > 0.3) {
            setAdvice({
                title: "Attention aux Cr├⌐dits",
                text: `${name}, ${totalPriceDette} F sont dehors. C'est beaucoup ! Tu devrais essayer de r├⌐cup├⌐rer cet argent avant de faire d'autres cr├⌐dits.`,
                voice: `${name}, fais attention. Trop de clients te doivent de l'argent. Tu as ${totalPriceDette} francs dehors. C'est plus de trente pour cent de ton capital. Tu devrais arr├¬ter les cr├⌐dits pour un moment.`,
                type: 'WARNING'
            });
        } else if (lowStock.length > 0) {
            const productNames = lowStock.slice(0, 2).map(p => p.audioName).join(' et ');
            setAdvice({
                title: "Stock ├á Renouveler",
                text: `Ton stock de ${productNames} est presque fini. Commande vite pour ne pas rater des ventes !`,
                voice: `${name}, ton stock baisse. Tu n'as presque plus de ${productNames}. Pense ├á commander chez ton livreur aujourd'hui.`,
                type: 'INFO'
            });
        } else if (balance > 5000) {
            setAdvice({
                title: "Bonne Gestion",
                text: "Tu as bien vendu aujourd'hui ! Tu as assez d'argent en caisse pour tes futures commandes.",
                voice: `Bravo ${name} ! Ta caisse est bien remplie aujourd'hui. Tu g├¿res tr├¿s bien ton commerce.`,
                type: 'SUCCESS'
            });
        } else {
            // Fallback to a random advice if no specific condition is met
            const randomIndex = Math.floor(Math.random() * advicesLine.length);
            setAdvice(advicesLine[randomIndex]);
        }
    };

    useEffect(() => {
        if (isOpen) {
            generateAdvice();
        }
    }, [isOpen, user, history, balance, stock, products]); // Added dependencies

    if (!isOpen) return null;

    return (
        <AnimatePresence>
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    onClick={onClose}
                    className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm"
                />

                <motion.div
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 20, opacity: 0 }}
                    className="relative w-full max-w-lg bg-white dark:bg-slate-900 rounded-2xl shadow-2xl overflow-hidden border border-slate-200 dark:border-slate-800"
                >
                    <button
                        onClick={onClose}
                        className="absolute right-6 top-6 w-10 h-10 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center text-slate-500 hover:text-slate-900 z-20"
                    >
                        <X size={24} />
                    </button>

                    <div className="p-6 md:p-8">
                        <div className="flex items-center gap-4 mb-6">
                            <div className={`p-3 rounded-xl ${advice?.type === 'WARNING' ? 'bg-rose-50 text-rose-500' :
                                advice?.type === 'SUCCESS' ? 'bg-emerald-50 text-emerald-600' :
                                    'bg-indigo-50 text-indigo-600'
                                }`}>
                                {advice?.type === 'WARNING' ? <AlertCircle size={24} /> :
                                    advice?.type === 'SUCCESS' ? <CheckCircle2 size={24} /> :
                                        <TrendingUp size={24} />}
                            </div>
                            <div>
                                <h2 className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-0.5">Conseil de l'Assistant</h2>
                                <h3 className="text-xl md:text-2xl font-bold text-slate-900 dark:text-white tracking-tight">{advice?.title}</h3>
                            </div>
                        </div>

                        <div className="bg-slate-50 dark:bg-slate-800/40 p-6 rounded-xl border border-slate-100 dark:border-slate-800 mb-6">
                            <p className="text-lg md:text-xl font-medium text-slate-700 dark:text-slate-200 leading-snug">
                                {advice?.text}
                            </p>
                        </div>

                        <div className="flex flex-col gap-3">
                            <button
                                onClick={() => advice && speakIfNecessary(advice.voice, 'NORMAL', true)}
                                className="w-full py-4 bg-primary text-white rounded-xl flex items-center justify-center gap-3 text-sm font-bold shadow-md active:scale-[0.98] transition-all"
                            >
                                <Volume2 size={20} />
                                ├ëCOUTER LE CONSEIL
                            </button>

                            <button
                                onClick={onClose}
                                className="w-full py-4 bg-slate-50 dark:bg-slate-800 text-slate-500 font-bold text-xs uppercase tracking-widest rounded-xl active:bg-slate-100 transition-colors"
                            >
                                J'ai compris
                            </button>
                        </div>
                    </div>

                    {/* D├⌐coration */}
                    <div className="absolute -left-10 -bottom-10 w-40 h-40 bg-amber-400/10 rounded-full blur-3xl pointer-events-none" />
                    <div className="absolute -right-10 -top-10 w-40 h-40 bg-blue-400/10 rounded-full blur-3xl pointer-events-none" />
                </motion.div>
            </div>
        </AnimatePresence>
    );
}

'use client';

import React, { useEffect, useRef, useState } from 'react';
import { Html5Qrcode, Html5QrcodeSupportedFormats } from 'html5-qrcode';
import { X, RefreshCcw, Camera, Zap, ZapOff } from 'lucide-react';
import { motion } from 'framer-motion';

interface BarcodeScannerProps {
    onScan: (decodedText: string) => void;
    onClose: () => void;
}

export const BarcodeScanner: React.FC<BarcodeScannerProps> = ({ onScan, onClose }) => {
    const scannerRef = useRef<Html5Qrcode | null>(null);
    const [facingMode, setFacingMode] = useState<"environment" | "user">("environment");
    const [isStarting, setIsStarting] = useState(true);
    const [scanError, setScanError] = useState<string | null>(null);
    const [flashOn, setFlashOn] = useState(false);

    // Fonction pour tenter d'allumer le flash
    const toggleFlash = async () => {
        try {
            if (scannerRef.current && scannerRef.current.getState() === 2) { // 2 = SCANNING
                await scannerRef.current.applyVideoConstraints({
                    advanced: [{ torch: !flashOn } as any]
                });
                setFlashOn(!flashOn);
            }
        } catch (err) {
            console.log("Torch non support├⌐e ou erreur", err);
            // On toggle state anyway to give UI feedback, though device may not have flash
            setFlashOn(!flashOn);
        }
    };

    useEffect(() => {
        const scanner = new Html5Qrcode("reader", {
            formatsToSupport: [
                Html5QrcodeSupportedFormats.EAN_13,
                Html5QrcodeSupportedFormats.EAN_8,
                Html5QrcodeSupportedFormats.CODE_128,
                Html5QrcodeSupportedFormats.UPC_A,
                Html5QrcodeSupportedFormats.UPC_E
            ],
            verbose: false
        });
        scannerRef.current = scanner;

        let isMounted = true;

        const startScanner = async () => {
            if (!isMounted) return;
            setIsStarting(true);
            setScanError(null);

            try {
                // S'assurer qu'aucun scanner ne tourne d├⌐j├á sur cet ├⌐l├⌐ment
                try {
                    if (scanner.isScanning) {
                        await scanner.stop();
                    }
                } catch (e) { }

                await new Promise(resolve => setTimeout(resolve, 300)); // D├⌐lai plus long pour la cam├⌐ra

                if (!isMounted) return;

                await scanner.start(
                    { facingMode },
                    {
                        fps: 10
                    },
                    (decodedText) => {
                        if (isMounted) {
                            // Jouer un petit bip natif via Web Audio API en cas de succ├¿s
                            try {
                                const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
                                const osc = ctx.createOscillator();
                                const gain = ctx.createGain();
                                osc.connect(gain);
                                gain.connect(ctx.destination);
                                osc.type = 'sine';
                                osc.frequency.setValueAtTime(800, ctx.currentTime);
                                gain.gain.setValueAtTime(0.1, ctx.currentTime);
                                osc.start(ctx.currentTime);
                                osc.stop(ctx.currentTime + 0.15); // Bip tr├¿s court de 150ms
                            } catch (e) { }

                            onScan(decodedText);
                        }
                    },
                    (errorMessage) => {
                        // On ignore les erreurs de frame "NotFound" pour ne pas polluer la console
                    }
                ).catch(err => {
                    // Si le d├⌐marrage ├⌐choue (ex: cam├⌐ra d├⌐j├á utilis├⌐e), on attend et on retente une fois
                    console.warn("Scanner start failed, retrying...", err);
                    setTimeout(() => {
                        if (isMounted && !scanner.isScanning) {
                            scanner.start({ facingMode }, { fps: 10 }, onScan, () => { }).catch(e => {
                                if (isMounted) setScanError("Impossible d'acc├⌐der ├á la cam├⌐ra. Veuillez rafra├«chir la page.");
                            });
                        }
                    }, 1000);
                });
            } catch (err: any) {
                console.error("Erreur de d├⌐marrage du scanner", err);
                if (isMounted) setScanError(err.message || "Erreur d'acc├¿s ├á la cam├⌐ra.");
            } finally {
                if (isMounted) setIsStarting(false);
            }
        };

        startScanner();

        return () => {
            isMounted = false;
            const cleanup = async () => {
                if (scannerRef.current) {
                    try {
                        if (scannerRef.current.isScanning) {
                            await scannerRef.current.stop();
                        }
                        scannerRef.current.clear();
                    } catch (e) {
                        console.error("Scanner cleanup error", e);
                    }
                }
            };
            cleanup();
        };
    }, [facingMode]); // Retir├⌐ onScan des d├⌐pendances pour ├⌐viter les red├⌐marrages inutiles si la prop change

    return (
        <motion.div
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 50 }}
            className="fixed inset-0 z-[200] flex flex-col bg-black overflow-hidden"
        >
            {/* Header / Contr├┤les (Haut) */}
            <div className="absolute top-0 inset-x-0 z-30 flex justify-between items-start p-6 pt-10">
                <button
                    onClick={onClose}
                    className="p-2 text-white active:opacity-70 transition-opacity bg-black/20 rounded-full"
                >
                    <X size={26} strokeWidth={2.5} />
                </button>
                <div className="flex gap-4">
                    <button
                        onClick={toggleFlash}
                        className="p-2 text-white active:opacity-70 transition-opacity bg-black/20 rounded-full"
                    >
                        {flashOn ? <Zap size={26} className="fill-white" strokeWidth={2} /> : <ZapOff size={26} strokeWidth={2.5} />}
                    </button>
                </div>
            </div>

            {/* Container for the scanner stream */}
            <div className="relative flex-1 w-full bg-black flex items-center justify-center mt-[-10vh]">
                {scanError ? (
                    <div className="text-rose-500 font-bold text-center px-4 uppercase text-xs z-20">
                        <Camera size={32} className="mx-auto mb-2 opacity-50" />
                        {scanError}
                        <button onClick={() => window.location.reload()} className="block mx-auto mt-4 px-4 py-2 bg-rose-500 text-white rounded-full">R├⌐essayer</button>
                    </div>
                ) : (
                    <>
                        {/* Le conteneur vid├⌐o HMTL5 QR Code rendu 100% de la div */}
                        <div id="reader" className="w-full h-full object-cover"></div>

                        {/* Scanner UI Overlay plus l├⌐ger pour ├⌐viter les crashs GPU de type "A├»e A├»e A├»e" (retrait de la shadow 4000px) */}
                        {!isStarting && !scanError && (
                            <div className="absolute inset-0 pointer-events-none z-10 flex flex-col items-center justify-center">
                                {/* Zone de scan centrale simplifi├⌐e */}
                                <div className="relative w-full max-w-sm aspect-[4/3] rounded-2xl border-2 border-dashed border-white/50 overflow-hidden mx-6">
                                    {/* Ligne anim├⌐e de Scan (Haut en bas) */}
                                    <div className="absolute top-0 left-0 right-0 h-1 bg-amber-500 shadow-[0_0_15px_#f59e0b] animate-scan-line"></div>
                                </div>
                                {/* Le texte en dessous */}
                                <div className="w-80 mt-6 text-center bg-black/50 px-4 py-2 rounded-full backdrop-blur-sm">
                                    <p className="text-white text-sm font-bold uppercase tracking-widest leading-tight">
                                        Placez le code-barres au centre
                                    </p>
                                </div>
                            </div>
                        )}
                    </>
                )}

                {isStarting && !scanError && (
                    <div className="absolute inset-0 flex items-center justify-center bg-black z-20">
                        <div className="w-10 h-10 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                    </div>
                )}
            </div>

            {/* Pas de boutons inf├⌐rieurs pour la vente (Focus sur le scan) */}

            <style jsx>{`
                @keyframes scanLine {
                    0% { top: 0%; opacity: 0; }
                    5% { opacity: 1; }
                    50% { top: calc(100% - 4px); opacity: 1; }
                    95% { opacity: 1; }
                    100% { top: 0%; opacity: 0; }
                }

                .animate-scan-line {
                    animation: scanLine 2.5s ease-in-out infinite;
                }

                /* Hide HTML5 QR Code default UI elements forcefully */
                #reader__dashboard_section_csr span,
                #reader__dashboard_section_swaplink,
                #reader__dashboard_section_csr div,
                #reader img,
                #reader__scan_region img {
                    display: none !important;
                }
                
                #reader {
                    width: 100% !important;
                    height: 100% !important;
