                            <div className="space-y-1">
                                <h3 className="font-bold text-slate-900 dark:text-white text-xs uppercase tracking-wider truncate">{p.name}</h3>
                                <p className="text-primary font-bold text-sm">{p.price} F</p>
                            </div>
                        </div>
                    );
