            }
        ]);
    };

    const handleWhatsAppRedirect = () => {
        const text = encodeURIComponent(`Bonjour l'├⌐quipe support, je suis ${merchantName} et je souhaite ${selectedTopic === 'CLOSURE' ? 'fermer mon compte' : 'poser une question'}.`);
