'use client';

import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { useAuth } from './AuthContext';

export interface Notification {
    id: string;
    target_id: string; // ID du commer├ºant ou 'ALL'
    title: string;
    message: string;
    type: 'INFO' | 'WARNING' | 'ALERT';
    is_read: boolean;
    created_at: number;
}

interface NotificationContextType {
    notifications: Notification[];
    unreadCount: number;
    sendNotification: (notification: Omit<Notification, 'id' | 'created_at' | 'is_read'>) => Promise<void>;
    markAsRead: (id: string) => Promise<void>;
    deleteNotification: (id: string) => Promise<void>;
}

const NotificationContext = createContext<NotificationContextType | undefined>(undefined);

export const NotificationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const [notifications, setNotifications] = useState<Notification[]>([]);

    // Simulation avec localStorage pour une op├⌐rationnalit├⌐ imm├⌐diate sans d├⌐pendance table DB
    // Mais structur├⌐ pour Supabase plus tard
    useEffect(() => {
        const saved = localStorage.getItem('app_notifications');
        if (saved) {
            setNotifications(JSON.parse(saved));
        }

        // ├ëcouter les changements dans localStorage pour le temps r├⌐el simul├⌐
        const handleStorage = () => {
            const updated = localStorage.getItem('app_notifications');
            if (updated) setNotifications(JSON.parse(updated));
        };
        window.addEventListener('storage', handleStorage);
        return () => window.removeEventListener('storage', handleStorage);
    }, []);

    const saveNotifications = (newItems: Notification[]) => {
        setNotifications(newItems);
        localStorage.setItem('app_notifications', JSON.stringify(newItems));
        // D├⌐clencher l'├⌐v├⌐nement manuellement car 'storage' ne se d├⌐clenche pas sur le m├¬me onglet
        window.dispatchEvent(new Event('storage'));
    };

    const sendNotification = async (data: Omit<Notification, 'id' | 'created_at' | 'is_read'>) => {
        const newNotif: Notification = {
            ...data,
            id: Math.random().toString(36).substr(2, 9),
            is_read: false,
            created_at: Date.now()
        };
        saveNotifications([newNotif, ...notifications]);
    };

    const markAsRead = async (id: string) => {
        saveNotifications(notifications.map(n => n.id === id ? { ...n, is_read: true } : n));
    };

    const deleteNotification = async (id: string) => {
        saveNotifications(notifications.filter(n => n.id !== id));
    };

    // Filtrer les notifications pour le commer├ºant actuel
    const relevantNotifications = user?.role === 'SUPERVISOR'
        ? notifications
        : notifications.filter(n => n.target_id === 'ALL' || n.target_id === user?.id);

    const unreadCount = relevantNotifications.filter(n => !n.is_read).length;

    return (
        <NotificationContext.Provider value={{
            notifications: relevantNotifications,
            unreadCount,
            sendNotification,
            markAsRead,
            deleteNotification
        }}>
            {children}
        </NotificationContext.Provider>
    );
};

export const useNotifications = () => {
    const context = useContext(NotificationContext);
    if (!context) {
        throw new Error('useNotifications must be used within a NotificationProvider');
    }
    return context;
};

'use client';

import React, { createContext, useContext, useState, useEffect, useCallback, ReactNode } from 'react';
import { products as initialProducts } from '../data/products';
import { Package, LucideIcon } from 'lucide-react';
import { supabase } from '@/lib/supabase';
import { useProfileContext } from './ProfileContext';
import { useError } from './ErrorContext';
import * as ProductService from '@/services/product.service';

export interface Product {
    id: string;
    name: string;
    icon: LucideIcon;
    imageUrl?: string;
    barcode?: string;
    price: number;
    color: string;
    iconColor: string;
    status?: string;
    audioName: string;
    category?: string;
}

interface ProductContextType {
    products: Product[];
    isLoading: boolean;
    addProduct: (product: Omit<Product, 'id'>, storeId?: string) => Promise<boolean>;
    updateProduct: (id: string, updates: Partial<Product>) => Promise<boolean>;
    deleteProduct: (id: string) => Promise<boolean>;
    resetProducts: () => Promise<boolean>;
}

const ProductContext = createContext<ProductContextType | undefined>(undefined);

export const ProductProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const { activeProfile } = useProfileContext();
    const [products, setProducts] = useState<Product[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const { addError } = useError();

    const mapRecordToProduct = useCallback((record: any): Product => ({
        id: record.id,
        name: record.name,
        price: record.price,
        imageUrl: record.image_url,
        barcode: record.barcode,
        color: record.color,
        iconColor: record.icon_color,
        audioName: record.audio_name,
        category: record.category,
        icon: initialProducts.find(ip => ip.name === record.name)?.icon || Package
    }), []);

    const fetchProducts = useCallback(async () => {
        if (!activeProfile) return;
        setIsLoading(true);
        try {
            // 1. Synchronisation Catch-up avec Supabase (ins├¿re proprement dans IndexedDB)
            await ProductService.syncProductsFromServer(activeProfile.id);

            // 2. Affiche ├á partir de la source de v├⌐rit├⌐ locale qui vient d'├¬tre mise ├á jour
            const productsFromService = await ProductService.getProductsForProfile(activeProfile.id);
            setProducts(productsFromService);
        } catch (error: any) {
            addError("Impossible de charger les produits.");
        } finally {
            setIsLoading(false);
        }
    }, [activeProfile, addError]);

    useEffect(() => {
        if (!activeProfile) {
            setProducts([]);
            return;
        }

        fetchProducts();

        const handleRealtimeUpdate = async (payload: any) => {
            await ProductService.processRealtimeEvent(payload);
            const { eventType, new: newRecord, old: oldRecord } = payload;
            switch (eventType) {
                case 'INSERT':
                    setProducts(prev => [...prev.filter(p => p.id !== newRecord.id), mapRecordToProduct(newRecord)]);
                    break;
                case 'UPDATE':
                    setProducts(prev => prev.map(p => p.id === newRecord.id ? mapRecordToProduct(newRecord) : p));
                    break;
                case 'DELETE':
                    if (oldRecord && oldRecord.id) {
                        setProducts(prev => prev.filter(p => p.id !== oldRecord.id));
                    }
                    break;
                default:
                    fetchProducts();
                    break;
            }
        };

        const subscription = supabase
            .channel(`product_changes_${activeProfile.id}`)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'products', filter: `store_id=in.(${activeProfile.id},GLOBAL)` }, handleRealtimeUpdate)
            .subscribe();

        return () => {
            supabase.removeChannel(subscription).catch(console.error);
        };
    }, [activeProfile, fetchProducts, mapRecordToProduct]);

    const addProduct = async (product: Omit<Product, 'id'>, storeId?: string): Promise<boolean> => {
        if (!activeProfile && !storeId) return false;
        const targetStoreId = storeId || activeProfile!.id;
        const tempId = crypto.randomUUID();
        const newProductForUI: Product = { id: tempId, ...product, icon: initialProducts.find(ip => ip.name === product.name)?.icon || Package };
        setProducts(prev => [...prev, newProductForUI]);
        try {
            await ProductService.addProduct(product, targetStoreId);
            return true;
        } catch (error: any) {
            addError(error.message || "Impossible d'ajouter le produit.");
            setProducts(prev => prev.filter(p => p.id !== tempId));
            return false;
        }
    };

    const updateProduct = async (id: string, updates: Partial<Product>): Promise<boolean> => {
        const originalProducts = products;
        const productToUpdate = originalProducts.find(p => p.id === id);
        if (!productToUpdate) return false;
        setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
        try {
            await ProductService.updateProduct(id, updates);
            return true;
        } catch (error: any) {
            addError(error.message || "Impossible de mettre ├á jour le produit.");
            setProducts(originalProducts);
            return false;
        }
    };

    const deleteProduct = async (id: string): Promise<boolean> => {
        const originalProducts = products;
        setProducts(prev => prev.filter(p => p.id !== id));
        try {
            await ProductService.deleteProduct(id);
            return true;
        } catch (error: any) {
            addError(error.message || "Impossible de supprimer le produit.");
            setProducts(originalProducts);
            return false;
        }
    };

    const resetProducts = async (): Promise<boolean> => {
        if (!activeProfile) return false;
        const originalProducts = products;
        setProducts(products.filter(p => p.category === 'GLOBAL'));
        try {
            await ProductService.resetProductsStore(activeProfile.id);
            return true;
        } catch (error: any) {
            addError(error.message || "La r├⌐initialisation a ├⌐chou├⌐.");
            setProducts(originalProducts);
            return false;
        }
    };

    return (
        <ProductContext.Provider value={{ products, isLoading, addProduct, updateProduct, deleteProduct, resetProducts }}>
            {children}
        </ProductContext.Provider>
    );
};

export const useProductContext = () => {
    const context = useContext(ProductContext);
    if (context === undefined) {
        throw new Error('useProductContext must be used within a ProductProvider');
    }
    return context;
};

