'use client';

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { supabase } from '@/lib/supabase';
import { useAuth } from './AuthContext';

export interface StoreProfile {
    id: string;
    name: string;
    merchantName: string;
    status: 'ACTIVE' | 'INACTIVE';
    createdAt: number;
    logo?: string;
    ownerRole?: string;
}

interface ProfileContextType {
    profiles: StoreProfile[];
    activeProfile: StoreProfile | null;
    addProfile: (profile: Omit<StoreProfile, 'id' | 'createdAt'>) => Promise<void>;
    updateProfile: (id: string, updates: Partial<StoreProfile>) => Promise<void>;
    deleteProfile: (id: string) => Promise<void>;
    setActiveProfile: (id: string) => void;
    refreshProfiles: () => Promise<void>;
}

const ProfileContext = createContext<ProfileContextType | undefined>(undefined);

export const ProfileProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, isAuthenticated } = useAuth();
    const [profiles, setProfiles] = useState<StoreProfile[]>([]);
    const [activeProfileId, setActiveProfileId] = useState<string | null>(null);

    const refreshProfiles = useCallback(async () => {
        if (!user) return;

        let query = supabase.from('stores').select('*, profiles:owner_id(full_name, role)');

        if (user.role !== 'SUPERVISOR') {
            query = query.eq('owner_id', user.id);
        }

        const { data, error } = await query;

        if (data && data.length === 0 && user.role === 'MERCHANT' && navigator.onLine) {
            // R├⌐trocompatibilit├⌐ : auto-cr├⌐ation pour les anciens comptes
            console.log('[ProfileContext] No store found, creating default store for merchant...');
            const { data: newStore, error: insertError } = await supabase.from('stores').insert([{
                owner_id: user.id,
                name: 'Ma Boutique',
                status: 'ACTIVE'
            }]).select().single();

            if (insertError) {
                console.error('[ProfileContext] Failed to create default store:', insertError.message);
                return;
            }

            if (newStore) {
                await refreshProfiles();
                return;
            }
        }

        if (data && data.length > 0) {
            const mapped: StoreProfile[] = data.map(s => ({
                id: s.id,
                name: s.name,
                merchantName: (s.profiles as any)?.full_name || 'Inconnu',
                ownerRole: (s.profiles as any)?.role || 'MERCHANT',
                status: s.status || 'ACTIVE',
                createdAt: new Date(s.created_at).getTime(),
                logo: s.logo_url
            }));
            setProfiles(mapped);

            const savedActiveId = localStorage.getItem('active_profile_id');
            if (savedActiveId && mapped.some(p => p.id === savedActiveId)) {
                setActiveProfileId(savedActiveId);
            } else if (mapped.length > 0) {
                setActiveProfileId(mapped[0].id);
            }
        }
    }, [user]);

    useEffect(() => {
        if (isAuthenticated && user) {
            refreshProfiles();
        } else {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setProfiles([]);
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setActiveProfileId(null);
        }
    }, [isAuthenticated, user, refreshProfiles]);

    const addProfile = async (profileData: Omit<StoreProfile, 'id' | 'createdAt'>) => {
        if (!user) return;

        const { data, error } = await supabase
            .from('stores')
            .insert([
                {
                    name: profileData.name,
                    owner_id: user.id,
                    status: profileData.status
                }
            ])
            .select()
            .single();

        if (data) {
            await refreshProfiles();
        }
    };

    const updateProfile = async (id: string, updates: Partial<StoreProfile>) => {
        const { error } = await supabase
            .from('stores')
            .update({
                name: updates.name,
                status: updates.status,
                logo_url: updates.logo
            })
            .eq('id', id);

        if (!error) {
            await refreshProfiles();
        }
    };

    const deleteProfile = async (id: string) => {
        const { error } = await supabase
            .from('stores')
            .delete()
            .eq('id', id);

        if (!error) {
            await refreshProfiles();
        }
    };

    const setActiveProfile = (id: string) => {
        setActiveProfileId(id);
        localStorage.setItem('active_profile_id', id);
    };

    const activeProfile = profiles.find(p => p.id === activeProfileId) || null;

    return (
        <ProfileContext.Provider value={{
            profiles,
            activeProfile,
            addProfile,
            updateProfile,
            deleteProfile,
            setActiveProfile,
            refreshProfiles
        }}>
            {children}
        </ProfileContext.Provider>
    );
};

export const useProfileContext = () => {
    const context = useContext(ProfileContext);
    if (!context) {
        throw new Error('useProfileContext must be used within a ProfileProvider');
    }
    return context;
};

'use client';

import React, { createContext, useContext, useState, useCallback, useEffect, useMemo } from 'react';
import { supabase } from '@/lib/supabase';
import { useProductContext } from './ProductContext';
import { useProfileContext } from './ProfileContext';
import { db } from '@/lib/db';
import { useSync } from './SyncContext';

interface StockLevels {
    [productId: string]: number;
}

interface StockContextType {
    stock: StockLevels;
    updateStock: (productId: string, amount: number) => Promise<void>;
    getStockLevel: (productId: string) => number;
}

const StockContext = createContext<StockContextType | undefined>(undefined);

export const StockProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { activeProfile } = useProfileContext();
    const { triggerSync } = useSync();
    const [stock, setStock] = useState<StockLevels>({});

    const fetchStock = useCallback(async () => {
        if (!activeProfile) return;

        try {
            // 1. Lire depuis IndexedDB
            const localStocks = await db.stocks.where('store_id').equals(activeProfile.id).toArray();
            const levels: StockLevels = {};
            localStocks.forEach(s => {
                levels[s.product_id] = s.quantity;
            });
            setStock(levels);

            // 2. Refresh depuis Supabase si online
            if (typeof navigator !== 'undefined' && navigator.onLine) {
                const { data, error } = await supabase
                    .from('stock')
                    .select('*')
                    .eq('store_id', activeProfile.id);

                if (data) {
                    for (const s of data) {
                        try {
                            await db.stocks.put({
                                id: `${activeProfile.id}_${s.product_id}`,
                                product_id: s.product_id,
                                quantity: s.quantity,
                                store_id: activeProfile.id,
                                synced: 1
                            });
                            levels[s.product_id] = s.quantity;
                        } catch (e) {
                            console.error("[StockContext] Error putting stock:", e);
                        }
                    }
                    setStock({ ...levels });
                }
            }
        } catch (err) {
            console.error("[StockContext] fetchStock error:", err);
        }
    }, [activeProfile]);

    useEffect(() => {
        let isMounted = true;
        let subscription: ReturnType<typeof supabase.channel> | null = null;

        if (activeProfile) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            fetchStock();

            // Real-time subscription to stock changes - FILTERED by store_id
            subscription = supabase
                .channel(`stock_changes_${activeProfile.id}`)
                .on(
                    'postgres_changes' as any,
                    {
                        event: '*',
                        table: 'stock',
                        schema: 'public',
                        filter: `store_id=eq.${activeProfile.id}`
                    },
                    (payload) => {
                        if (isMounted) {
                            console.log("[StockContext] Realtime update recived:", payload);
                            fetchStock();
                        }
                    }
                )
                .subscribe();

        } else {
            setStock({});
        }

        return () => {
            isMounted = false;
            if (subscription) {
                // Async cleanup to prevent UI blocking and ensure socket is properly destroyed
                supabase.removeChannel(subscription).catch(console.error);
            }
        };
    }, [activeProfile, fetchStock]);

    const updateStock = useCallback(async (productId: string, amount: number) => {
        if (!activeProfile) return;

        try {
            // Optimistic update
            const currentQty = stock[productId] || 0;
            const newQty = Math.max(0, currentQty + amount);

            setStock(current => ({
                ...current,
                [productId]: newQty
            }));

            // 1. Sauvegarde locale
            await db.stocks.put({
                id: `${activeProfile.id}_${productId}`,
                product_id: productId,
                quantity: newQty,
                store_id: activeProfile.id,
                synced: 0
            });

            // 2. File de synchro
            await db.syncQueue.add({
                action: 'UPDATE_STOCK',
                payload: {
                    product_id: productId,
                    quantity: amount,
                    store_id: activeProfile.id
                },
                status: 'PENDING',
                retry_count: 0,
                created_at: Date.now()
            });

            // Forcer synchro si en ligne
            if (navigator.onLine) {
                triggerSync();
            }
        } catch (err) {
            console.error("[StockContext] updateStock error:", err);
        }
    }, [activeProfile, stock, triggerSync]);

    const getStockLevel = useCallback((productId: string) => stock[productId] || 0, [stock]);

    return (
        <StockContext.Provider value={{ stock, updateStock, getStockLevel }}>
            {children}
        </StockContext.Provider>
    );
};

export const useStockContext = () => {
    const context = useContext(StockContext);
    if (!context) {
        throw new Error('useStockContext must be used within a StockProvider');
    }
    return context;
};

'use client';

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { db } from '@/lib/db';
import { supabase } from '@/lib/supabase';

interface SyncContextType {
    isOnline: boolean;
    isSyncing: boolean;
    syncPendingCount: number;
    lastSyncError: string | null;
    syncAll: (forceRetry?: boolean) => Promise<void>;
    triggerSync: () => Promise<void>;
}

const SyncContext = createContext<SyncContextType | undefined>(undefined);

export const SyncProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [isOnline, setIsOnline] = useState(typeof navigator !== 'undefined' ? navigator.onLine : true);
    const isSyncingRef = useRef(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [syncPendingCount, setSyncPendingCount] = useState(0);
    const [lastSyncError, setLastSyncError] = useState<string | null>(null);

    const updatePendingCount = useCallback(async () => {
        const count = await db.syncQueue.count();
        setSyncPendingCount(count);
    }, []);

    const processQueue = useCallback(async (forceRetry: boolean = false) => {
        if (!navigator.onLine || isSyncingRef.current) return;

        // Traiter PENDING et retenter les ERROR
        // Si forceRetry est vrai, on inclut aussi les FAILED
        const statusFilter = forceRetry ? ['PENDING', 'ERROR', 'FAILED'] : ['PENDING', 'ERROR'];

        const pending = await db.syncQueue
            .where('status')
            .anyOf(statusFilter)
            .toArray();

        if (pending.length === 0) {
            updatePendingCount();
            return;
        }

        // --- TRI DE LA FILE : C'est ici qu'on g├¿re la priorit├⌐ ---
        // Les cr├⌐ations de produits doivent partir avant tout mouvement de stock
        pending.sort((a, b) => {
            const priorityActions = ['ADD_PRODUCT']; // On peut rajouter d'autres if needed

            const aIsPriority = priorityActions.includes(a.action);
            const bIsPriority = priorityActions.includes(b.action);

            if (aIsPriority && !bIsPriority) return -1;
            if (!aIsPriority && bIsPriority) return 1;

            // En cas d'├⌐galit├⌐ sur la priorit├⌐, on garde l'ordre chronologique
            return (a.created_at || 0) - (b.created_at || 0);
        });

        isSyncingRef.current = true;
        setIsSyncing(true);
        console.log(`[Sync] Processing ${pending.length} pending/error actions...`);

        for (const item of pending) {
            try {
                let success = false;
                let errorDetails = null;

                switch (item.action) {
                    case 'ADD_TRANSACTION': {
                        const { error: tError } = await supabase.from('transactions').insert([item.payload]);
                        if (!tError || tError.code === '23505') success = true;
                        else errorDetails = tError;
                        break;
                    }
                    case 'UPDATE_STOCK': {
                        const { product_id, quantity } = item.payload;

                        // 1. R├⌐cup├⌐rer la quantit├⌐ actuelle pour faire un calcul relatif
                        // Note: store_id n'existe pas dans la table stock sur Supabase
                        const { data: currentStock, error: fetchError } = await supabase
                            .from('stock')
                            .select('quantity')
                            .eq('product_id', product_id)
                            .maybeSingle();

                        if (fetchError) {
                            errorDetails = fetchError;
                            break;
                        }

                        const newQty = Math.max(0, (currentStock?.quantity || 0) + quantity);

                        // 2. Mise ├á jour via upsert sur product_id (cl├⌐ primaire attendue)
                        const { error: sError } = await supabase
                            .from('stock')
                            .upsert(
                                {
                                    product_id,
                                    quantity: newQty
                                }
                            );

                        if (!sError) {
                            success = true;
                        } else if (sError.code === '23503') {
                            // Violation de cl├⌐ ├⌐trang├¿re ! Le produit manque probablement dans Supabase.
                            console.warn(`[Sync] Product ${product_id} missing in Supabase. Attempting auto-fix...`);

                            const localProd = await db.products.get(product_id);
                            if (localProd) {
                                // Tenter d'ins├⌐rer le produit manquant proprement
                                const payload: {
                                    id: string;
                                    store_id: string;
                                    name: string;
                                    price: number;
                                    color: string;
                                    icon_color: string;
                                    audio_name: string;
                                    image_url?: string;
                                    barcode?: string;
                                    category?: string;
                                } = {
                                    id: localProd.id,
                                    store_id: localProd.store_id,
                                    name: localProd.name,
                                    price: localProd.price,
                                    color: localProd.color,
                                    icon_color: localProd.icon_color,
                                    audio_name: localProd.audio_name
                                };
                                if (localProd.image_url) payload.image_url = localProd.image_url;
                                if (localProd.barcode) payload.barcode = localProd.barcode;
                                if (localProd.category) payload.category = localProd.category;

                                const { error: prodError } = await supabase
                                    .from('products')
                                    .insert([payload]);

                                if (!prodError || prodError.code === '23505') {
                                    // Succ├¿s ou d├⌐j├á pr├⌐sent, on retente l'upsert du stock
                                    const { error: retryStock } = await supabase
                                        .from('stock')
                                        .upsert({ product_id, quantity: newQty });

                                    if (!retryStock) success = true;
                                    else errorDetails = retryStock;
                                } else if (prodError.message.includes('barcode') || prodError.message.includes('category') || prodError.message.includes('image_url')) {
                                    // Deuxi├¿me tentative sans les colonnes optionnelles si elles manquent dans le sch├⌐ma cloud
                                    const retryPayload = { ...payload };
                                    delete retryPayload.barcode;
                                    delete retryPayload.category;
                                    delete retryPayload.image_url;
                                    const { error: retryProd } = await supabase.from('products').insert([retryPayload]);
                                    if (!retryProd || retryProd.code === '23505') {
                                        const { error: retryStock } = await supabase.from('stock').upsert({ product_id, quantity: newQty });
                                        if (!retryStock) success = true;
                                        else errorDetails = retryStock;
                                    } else {
                                        errorDetails = retryProd;
                                    }
                                } else {
                                    errorDetails = prodError;
                                }
                            } else {
                                errorDetails = sError;
                            }
                        } else {
                            errorDetails = sError;
                        }
                        break;
                    }
                    case 'MARK_PAID': {
                        const { id: tid } = item.payload;
                        const { error: pError } = await supabase
                            .from('transactions')
                            .update({ status: 'PAY├ë' })
                            .eq('id', tid);
                        if (!pError) success = true;
                        else errorDetails = pError;
                        break;
                    }
                    case 'ADD_PRODUCT': {
                        const { id, store_id, name, price, color, icon_color, audio_name, image_url, barcode, category } = item.payload;

                        // Construire le payload de mani├¿re robuste
                        const payload: {
                            id: string;
                            store_id: string;
                            name: string;
                            price: number;
                            color: string;
                            icon_color: string;
                            audio_name: string;
                            category?: string;
                            image_url?: string;
                            barcode?: string;
                        } = {
                            id,
                            store_id,
                            name,
                            price,
                            color: color || '#F1F5F9',
                            icon_color: icon_color || '#64748B',
                            audio_name: audio_name || name
                        };

                        // Ajouter les colonnes optionnelles seulement si elles existent dans le payload
                        // et on va les prot├⌐ger pour ├⌐viter les erreurs de sch├⌐ma cloud
                        if (category) payload.category = category;
                        if (image_url) payload.image_url = image_url;
                        if (barcode) payload.barcode = barcode;

                        const { error: apError } = await supabase
                            .from('products')
                            .insert([payload]);

                        if (!apError || apError.code === '23505') success = true;
                        else if (apError.message.includes('barcode') || apError.message.includes('image_url') || apError.message.includes('category')) {
                            // Si l'erreur mentionne sp├⌐cifiquement une colonne manquante, on retente sans les colonnes optionnelles
                            console.warn(`[Sync] Retrying ADD_PRODUCT without optional columns due to schema mismatch...`);
                            const retryPayload = { ...payload };
                            delete retryPayload.barcode;
                            delete retryPayload.image_url;
                            delete retryPayload.category;
                            const { error: retryError } = await supabase.from('products').insert([retryPayload]);
                            if (!retryError || retryError.code === '23505') success = true;
                            else errorDetails = retryError;
                        } else {
                            errorDetails = apError;
                        }
                        break;
                    }
                    case 'UPDATE_PRODUCT': {
                        const { id: upid, ...updates } = item.payload;
                        // Mapper camelCase vers snake_case pour les mises ├á jour
                        const mappedUpdates: Record<string, unknown> = {};
                        if (updates.name) mappedUpdates.name = updates.name;
                        if (updates.price) mappedUpdates.price = updates.price;
                        if (updates.audioName) mappedUpdates.audio_name = updates.audioName;
                        if (updates.imageUrl) mappedUpdates.image_url = updates.imageUrl;
                        if (updates.barcode) mappedUpdates.barcode = updates.barcode;
                        if (updates.color) mappedUpdates.color = updates.color;
                        if (updates.iconColor) mappedUpdates.icon_color = updates.iconColor;
                        if (updates.category) mappedUpdates.category = updates.category;

                        const { error: upError } = await supabase
                            .from('products')
                            .update(mappedUpdates)
                            .eq('id', upid);
                        if (!upError) success = true;
                        else errorDetails = upError;
                        break;
                    }
                    case 'DELETE_PRODUCT': {
                        const { id: dpid } = item.payload;
                        const { error: dpError } = await supabase
                            .from('products')
                            .delete()
                            .eq('id', dpid);
                        if (!dpError) success = true;
                        else errorDetails = dpError;
                        break;
                    }
                }

                if (success) {
                    await db.syncQueue.delete(item.id!);
                    updatePendingCount();
                    setLastSyncError(null);
                } else {
                    const msg = errorDetails?.message || JSON.stringify(errorDetails) || "Erreur inconnue";
                    console.error(`[Sync] Action ${item.action} failed:`, msg);
                    setLastSyncError(`[${item.action}] ${msg}`);

                    const nextRetry = (item.retry_count || 0) + 1;
                    if (nextRetry >= 3) {
                        await db.syncQueue.update(item.id!, {
                            status: 'FAILED',
                            retry_count: nextRetry
                        });
                    } else {
                        await db.syncQueue.update(item.id!, {
                            status: 'ERROR',
                            retry_count: nextRetry
                        });
                    }
                }
            } catch (err) {
                console.error("[Sync] Fatal error processing item:", err);
                try {
                    const nextRetry = (item.retry_count || 0) + 1;
                    await db.syncQueue.update(item.id!, {
                        status: nextRetry >= 3 ? 'FAILED' : 'ERROR',
                        retry_count: nextRetry
                    });
                } catch (updateErr) {
                    console.error("[Sync] Could not update failed sync queue item", updateErr);
                }
            }
        }

        isSyncingRef.current = false;
        setIsSyncing(false);
        updatePendingCount();
    }, [updatePendingCount]);

    useEffect(() => {
        const handleOnline = () => {
            setIsOnline(true);
            processQueue();
        };
        const handleOffline = () => setIsOnline(false);

        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);

        // Initial sync: process queue immediately on startup
        // eslint-disable-next-line react-hooks/set-state-in-effect
        updatePendingCount();
        if (typeof navigator !== 'undefined' && navigator.onLine) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            processQueue();
        }

        // More frequent periodic sync (every 30s) - reduced from 10s to improve battery/CPU
        const interval = setInterval(() => {
            if (typeof navigator !== 'undefined' && navigator.onLine) processQueue();
        }, 30000);

        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
            clearInterval(interval);
        };
    }, [processQueue, updatePendingCount]);

    return (
        <SyncContext.Provider value={{
            isOnline,
            isSyncing,
            syncPendingCount,
            lastSyncError,
            syncAll: (retry?: boolean) => processQueue(retry),
            triggerSync: () => processQueue(false)
        }}>
            {children}
        </SyncContext.Provider>
    );
};

export const useSync = () => {
    const context = useContext(SyncContext);
    if (!context) throw new Error('useSync must be used within SyncProvider');
    return context;
};

