'use client';

import React, { createContext, useContext, useState, useCallback, useRef, useEffect } from 'react';

export type SpeechPriority = 'LOW' | 'NORMAL' | 'HIGH';
export type VerbosityLevel = 'NORMAL' | 'SILENT';

interface VoiceContextType {
    isSpeaking: boolean;
    isListening: boolean;
    transcript: string;
    verbosity: VerbosityLevel;
    setVerbosity: (level: VerbosityLevel) => void;
    speak: (text: string, autoListen?: boolean) => void;
    speakIfNecessary: (text: string, priority?: SpeechPriority, autoListen?: boolean) => void;
    listen: () => void;
    stopSpeaking: () => void;
    clearTranscript: () => void;
}

const VoiceContext = createContext<VoiceContextType | undefined>(undefined);

export const VoiceProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [isSpeaking, setIsSpeaking] = useState(false);
    const [isListening, setIsListening] = useState(false);
    const [transcript, setTranscript] = useState('');
    const [verbosity, setVerbosity] = useState<VerbosityLevel>('NORMAL');
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const recognitionRef = useRef<any>(null);

    // Initialiser les pr├⌐f├⌐rences au montage
    useEffect(() => {
        const savedVerbosity = localStorage.getItem('assistant_verbosity');
        if (savedVerbosity === 'SILENT') setVerbosity('SILENT');
    }, []);

    const handleSetVerbosity = useCallback((level: VerbosityLevel) => {
        setVerbosity(level);
        localStorage.setItem('assistant_verbosity', level);
    }, []);

    // Refs to break circular dependency
    const speakRef = useRef<(text: string, autoListen?: boolean) => void>(undefined);
    const listenRef = useRef<() => void>(undefined);

    const stopSpeaking = useCallback(() => {
        if (typeof window !== 'undefined' && 'speechSynthesis' in window) {
            window.speechSynthesis.cancel();
            setIsSpeaking(false);
        }
    }, []);

    const listen = useCallback(() => {
        if (typeof window !== 'undefined' && ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window)) {
            if (recognitionRef.current) {
                try {
                    recognitionRef.current?.abort();
                } catch { }
            }

            const SpeechRecognitionConstructor = (window as unknown as { webkitSpeechRecognition: any; SpeechRecognition: any }).webkitSpeechRecognition || (window as unknown as { SpeechRecognition: any }).SpeechRecognition;
            const recognition = new SpeechRecognitionConstructor();
            recognitionRef.current = recognition;

            recognition.lang = 'fr-FR';
            recognition.continuous = false;
            recognition.interimResults = false;

            recognition.onstart = () => setIsListening(true);
            recognition.onend = () => setIsListening(false);

            recognition.onerror = (event: { error: string }) => {
                setIsListening(false);
                if (event.error === 'not-allowed') {
                    speakRef.current?.("Je ne peux pas t'entendre, tu dois autoriser le microphone.");
                } else if (event.error === 'network') {
                    speakRef.current?.("Probl├¿me de connexion, v├⌐rifie ton internet.");
                } else {
                    speakRef.current?.("D├⌐sol├⌐, je n'ai pas bien entendu.");
                }
            };

            recognition.onresult = (event: { results: { transcript: string }[][] }) => {
                const text = event.results[0][0].transcript;
                setTranscript(text);
                speakRef.current?.(`J'ai entendu : ${text}`);
            };

            recognition.start();
        } else {
            speakRef.current?.("Pardon, je ne peux pas t'├⌐couter sur ce t├⌐l├⌐phone.");
        }
    }, []);

    useEffect(() => {
        listenRef.current = listen;
    }, [listen]);

    const speak = useCallback((text: string, autoListen: boolean = false) => {
        if (typeof window !== 'undefined' && 'speechSynthesis' in window) {
            window.speechSynthesis.cancel(); // Stop old speech

            // Nettoyage : Transformer les mots en MAJUSCULES (ex: ADJO) en minuscules (ex: Adjo)
            // Cela ├⌐vite que le moteur TTS n'├⌐p├¿le le mot lettre par lettre.
            const sanitizedText = text.replace(/\b([A-Z])([A-Z]{1,})\b/g, (match, p1, p2) => {
                return p1 + p2.toLowerCase();
            });

            const utterance = new SpeechSynthesisUtterance(sanitizedText);
            utterance.lang = 'fr-FR';
            utterance.rate = 0.95; // Slightly faster for responsiveness
            utterance.onstart = () => setIsSpeaking(true);
            utterance.onend = () => {
                setIsSpeaking(false);
                if (autoListen) {
                    setTimeout(() => listenRef.current?.(), 300); // Petit d├⌐lai pour ├⌐viter l'├⌐cho
                }
            };
            window.speechSynthesis.speak(utterance);
        }
    }, []);

    const speakIfNecessary = useCallback((text: string, priority: SpeechPriority = 'LOW', autoListen: boolean = false) => {
        // En mode silencieux, seules les paroles HAUTE priorit├⌐ (erreurs, alertes) passent.
        if (verbosity === 'SILENT' && priority !== 'HIGH') {
            // Optionnel : on pourrait jouer un petit 'bip' court ici si on a un Earcon (audio court).
            return;
        }

        // En mode normal (ou si c'est prioritaire), on lit le texte complet.
        speak(text, autoListen);
    }, [verbosity, speak]);

    useEffect(() => {
        speakRef.current = speak;
    }, [speak]);

    const clearTranscript = useCallback(() => {
        setTranscript('');
    }, []);

    return (
        <VoiceContext.Provider value={{
            isSpeaking,
            isListening,
            transcript,
            verbosity,
            setVerbosity: handleSetVerbosity,
            speak,
            speakIfNecessary,
            listen,
            stopSpeaking,
            clearTranscript
        }}>
            {children}
        </VoiceContext.Provider>
    );
};

export const useVoiceContext = () => {
    const context = useContext(VoiceContext);
    if (!context) {
        throw new Error('useVoiceContext must be used within a VoiceProvider');
    }
    return context;
};
